import type { HandbookDocumentContent } from "../types";

const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">PRACTICE · WORKFLOW SETUP</div>\n  <div class=\"nav-title\">실무 준비 · 성장 로드맵과 작업 루프</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>통합 문서</a>\n  <a href=\"#doc-roadmap\"><span class=\"code\">DOC</span>풀스택 성장 로드맵</a>\n  <a href=\"#doc-faq\"><span class=\"code\">DOC</span>개발자 FAQ·트러블슈팅</a>\n  <a href=\"#doc-machine\"><span class=\"code\">DOC</span>새 PC 환경 설정</a>\n  <a href=\"#doc-playbook\"><span class=\"code\">DOC</span>실무 플레이북</a>\n  <a href=\"#doc-roadmap\"><span class=\"code\">SRC</span>풀스택 성장 로드맵</a>\n<a href=\"#roadmap-ch1\"><span class=\"code\">FS-01</span>목적과 기준</a>\n  <a href=\"#roadmap-ch2\"><span class=\"code\">FS-02</span>역량 지도</a>\n  <a href=\"#roadmap-ch3\"><span class=\"code\">FS-03</span>학습 순서</a>\n  <a href=\"#roadmap-ch4\"><span class=\"code\">FS-04</span>경계면 체크리스트</a>\n  <a href=\"#roadmap-ch5\"><span class=\"code\">FS-05</span>캡스톤 과제</a>\n  <a href=\"#roadmap-ch6\"><span class=\"code\">FS-06</span>품질 기준</a>\n  <a href=\"#roadmap-ch7\"><span class=\"code\">FS-07</span>고급 개발자 루브릭</a>\n  <a href=\"#roadmap-ch8\"><span class=\"code\">FS-08</span>실전 훈련 루프</a>\n  <a href=\"#roadmap-ch9\"><span class=\"code\">FS-09</span>실전 경험 시뮬레이터</a>\n  <a href=\"#doc-faq\"><span class=\"code\">SRC</span>개발자 FAQ·트러블슈팅</a>\n<a href=\"#faq-ch15\"><span class=\"code\">FAQ-15</span>증상 기반 빠른 진입</a>\n  <a href=\"#faq-ch1\"><span class=\"code\">FAQ-01</span>질문을 문제 정의로 바꾸기</a>\n  <a href=\"#faq-ch2\"><span class=\"code\">FAQ-02</span>로컬은 되는데 CI·운영은 실패</a>\n  <a href=\"#faq-ch3\"><span class=\"code\">FAQ-03</span>빌드·의존성·버전 충돌</a>\n  <a href=\"#faq-ch4\"><span class=\"code\">FAQ-04</span>환경변수·쿠키·CORS·시크릿</a>\n  <a href=\"#faq-ch5\"><span class=\"code\">FAQ-05</span>DB 마이그레이션·락·시딩</a>\n  <a href=\"#faq-ch6\"><span class=\"code\">FAQ-06</span>\"느려요\" 성능 triage</a>\n  <a href=\"#faq-ch7\"><span class=\"code\">FAQ-07</span>테스트가 로컬/CI에서 다르게 실패</a>\n  <a href=\"#faq-ch8\"><span class=\"code\">FAQ-08</span>git·PR·리뷰 사고 복구</a>\n  <a href=\"#faq-ch9\"><span class=\"code\">FAQ-09</span>AI 생성 코드 검증 부채</a>\n  <a href=\"#faq-ch10\"><span class=\"code\">FAQ-10</span>장애 보고·에스컬레이션</a>\n  <a href=\"#faq-ch11\"><span class=\"code\">FAQ-11</span>동시성·멱등성·중복 처리</a>\n  <a href=\"#faq-ch12\"><span class=\"code\">FAQ-12</span>로그·메트릭·트레이스</a>\n  <a href=\"#faq-ch13\"><span class=\"code\">FAQ-13</span>보안·권한·데이터 삭제</a>\n  <a href=\"#faq-ch14\"><span class=\"code\">FAQ-14</span>문서화·온보딩·지식 이전</a>\n  <a href=\"#faq-ch16\"><span class=\"code\">FAQ-16</span>60문항 문제 해결 매트릭스</a>\n  <a href=\"#faq-ch17\"><span class=\"code\">FAQ-17</span>운영 준비도 루브릭</a>\n  <a href=\"#faq-ch18\"><span class=\"code\">FAQ-18</span>참고 기준과 한계</a>\n  <a href=\"#doc-machine\"><span class=\"code\">SRC</span>새 PC 환경 설정</a>\n<a href=\"#machine-ch1\"><span class=\"code\">SETUP-01</span>시작 전 — 큰 그림</a>\n  <a href=\"#machine-ch2\"><span class=\"code\">SETUP-02</span>1단계 — 시스템 기반</a>\n  <a href=\"#machine-ch3\"><span class=\"code\">SETUP-03</span>2단계 — Claude Code 진입점</a>\n  <a href=\"#machine-ch4\"><span class=\"code\">SETUP-04</span>3단계 — MCP 서버 연결</a>\n  <a href=\"#machine-ch5\"><span class=\"code\">SETUP-05</span>4단계 — zsh + cmux</a>\n  <a href=\"#machine-ch6\"><span class=\"code\">SETUP-06</span>5단계 — Obsidian 컨텍스트</a>\n  <a href=\"#machine-ch7\"><span class=\"code\">SETUP-07</span>6단계 — 언어 런타임 mise</a>\n  <a href=\"#machine-ch8\"><span class=\"code\">SETUP-08</span>7단계 — Git·GitHub·dotfiles</a>\n  <a href=\"#machine-ch9\"><span class=\"code\">SETUP-09</span>Windows PC 셋업</a>\n  <a href=\"#machine-ch10\"><span class=\"code\">SETUP-10</span>검증 + cmux 운용</a>\n  <a href=\"#machine-ch11\"><span class=\"code\">SETUP-11</span>치트시트</a>\n  <a href=\"#doc-playbook\"><span class=\"code\">SRC</span>실무 플레이북</a>\n<a href=\"#playbook-ch1\"><span class=\"code\">PLAY-01</span>실무 감각은 어떻게 기르는가</a>\n  <a href=\"#playbook-ch2\"><span class=\"code\">PLAY-02</span>로컬 DB 리셋·시더</a>\n  <a href=\"#playbook-ch3\"><span class=\"code\">PLAY-03</span>포트·프로세스 꼬임</a>\n  <a href=\"#playbook-ch4\"><span class=\"code\">PLAY-04</span>마이그레이션·스키마 드리프트</a>\n  <a href=\"#playbook-ch5\"><span class=\"code\">PLAY-05</span>빌드·의존성·런타임</a>\n  <a href=\"#playbook-ch6\"><span class=\"code\">PLAY-06</span>\"느려요\"를 추적하는 순서</a>\n  <a href=\"#playbook-ch7\"><span class=\"code\">PLAY-07</span>운영 장애 미니 런북</a>\n  <a href=\"#playbook-ch8\"><span class=\"code\">PLAY-08</span>git 사고 복구</a>\n  <a href=\"#playbook-ch9\"><span class=\"code\">PLAY-09</span>환경설정·시크릿</a>\n  <a href=\"#playbook-ch10\"><span class=\"code\">PLAY-10</span>체크리스트 모음</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : PRACTICE-WORKFLOW-SETUP</span>\n    <span>SCOPE : ROADMAP · FAQ · MACHINE SETUP · PLAYBOOK</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>실무 준비와 작업 루프</h1>\n  <p class=\"hero-sub\">풀스택 성장 로드맵, 개발자 FAQ·트러블슈팅, 새 PC 환경 설정, 실무 플레이북을 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED HANDBOOK PATH · SOURCES : 4 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>통합 문서</h2></div>\n<p class=\"lede\">아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다.</p>\n<ul><li>풀스택 성장 로드맵</li><li>개발자 FAQ·트러블슈팅</li><li>새 PC 환경 설정</li><li>실무 플레이북</li></ul>\n</section>\n\n<section id=\"doc-roadmap\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>풀스택 성장 로드맵</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : FULLSTACK-ROADMAP-V1</span>\n    <span>SCOPE : FE · BE · DB · NETWORK · DEVOPS · DESIGN · OPS</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>풀스택 성장 로드맵</h1>\n  <p class=\"hero-sub\">풀스택 역량은 프론트엔드와 백엔드 문법을 모두 아는 것이 아니라 <strong>사용자 행동, API 계약, 데이터 정합성, 배포, 운영 신호를 하나의 변경 흐름으로 연결해 설명하고 실행하는 능력</strong>입니다.</p>\n  <div class=\"hero-meta\">TARGET : 프론트엔드 경험을 기반으로 백엔드·인프라·운영까지 확장하는 개발자<br>STANCE : 읽는 순서 · 실전 과제 · 품질 기준을 함께 제공</div>\n</header>\n\n<section id=\"roadmap-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-01</span><h2>목적과 기준</h2></div>\n<p class=\"lede\">이 핸드북의 목적은 지식 목록을 넓히는 것이 아니라, 하나의 기능을 제품 경험에서 운영까지 끝까지 책임지는 판단 체계를 만드는 것입니다.</p>\n<table>\n<tr><th>관점</th><th>단편 지식</th><th>풀스택 판단</th></tr>\n<tr><td>기능 구현</td><td>화면과 API를 각각 만든다</td><td>사용자 흐름, API 계약, 데이터 상태 전이를 함께 설계한다</td></tr>\n<tr><td>데이터</td><td>CRUD가 동작한다</td><td>트랜잭션, 동시성, 마이그레이션, 감사 추적을 고려한다</td></tr>\n<tr><td>배포</td><td>서버에 올린다</td><td>빌드 산출물, 설정, secret, rollback, health check를 설계한다</td></tr>\n<tr><td>운영</td><td>오류가 나면 로그를 본다</td><td>로그·메트릭·트레이스·알림으로 실패 위치와 영향 범위를 좁힌다</td></tr>\n<tr><td>제품 품질</td><td>요구사항대로 만든다</td><td>접근성, 성능, 보안, 사용성, 회복 경로까지 검증한다</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">핵심 전환</span>\n<p>풀스택 학습의 중심 질문은 “무엇을 더 배울까”가 아니라 <strong>“이 변경이 사용자에게 도달할 때 어떤 계약, 상태, 장애 모드를 만드는가”</strong>입니다. 이 질문을 기준으로 각 핸드북을 연결해 읽습니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-02</span><h2>역량 지도</h2></div>\n<p class=\"lede\">풀스택 역량은 여섯 축으로 나눠 익히면 누락이 줄어듭니다. 각 축은 독립 과목이 아니라 하나의 변경 안에서 동시에 만납니다.</p>\n<table>\n<tr><th>축</th><th>핵심 질문</th><th>연결 문서</th></tr>\n<tr><td>제품·디자인</td><td>사용자가 어떤 목표를 어떤 순서로 달성하는가</td><td>디자인 개요, 사용자 흐름, 폼과 입력 경험</td></tr>\n<tr><td>프론트엔드</td><td>상태, 렌더링, 접근성, 에러 UX가 안정적인가</td><td>프론트엔드 개요, 성능과 지표, 테스트 전략</td></tr>\n<tr><td>API·백엔드</td><td>계약, 권한, 실패, 멱등성, 동시성을 어떻게 다루는가</td><td>백엔드 개요, 인증과 보안, 아키텍처 패턴</td></tr>\n<tr><td>데이터</td><td>정합성, 조회 성능, 스키마 변경을 어떻게 보장하는가</td><td>DB, JPA, DB 스키마·시딩</td></tr>\n<tr><td>인프라·DevOps</td><td>빌드·배포·설정·네트워크가 재현 가능한가</td><td>Docker와 배포, DevOps 개요, 네트워크 인프라</td></tr>\n<tr><td>운영</td><td>문제가 생겼을 때 감지·완화·복구가 가능한가</td><td>관측 가능성, 로그·커스텀 명령, 실무 플레이북</td></tr>\n<tr><td>언어 기반</td><td>JavaScript/TypeScript와 Java 언어의 타입, 런타임, 동시성, 에러 모델을 설명할 수 있는가</td><td>프론트엔드 개요, Java 예시, Spring Boot 예시</td></tr>\n<tr><td>컴퓨터 과학</td><td>자료구조·알고리즘을 성능 판단과 코드 단순성의 근거로 사용할 수 있는가</td><td>백엔드 개요, DB 실행계획, 실무 플레이북</td></tr>\n<tr><td>협업·변경 관리</td><td>Git 협업, 코드 리뷰, 리팩토링, ADR을 통해 변경 이유와 위험을 남기는가</td><td>DevOps 소프트웨어 전달, 형상 관리, 실무 플레이북</td></tr>\n<tr><td>API 계약</td><td>REST, OpenAPI, 에러 코드, 버전 정책을 클라이언트와 서버가 공유하는 계약으로 관리하는가</td><td>백엔드 개요, 아키텍처 패턴, 프론트엔드 API 연동</td></tr>\n<tr><td>클라우드 기본</td><td>AWS·GCP·Azure의 IAM, 네트워크, 컴퓨트, 스토리지, 로그 경계를 구분하는가</td><td>네트워크 인프라, DevOps, 보안과 신뢰성</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">평가 산출물</span>\n<p>각 축은 읽었다는 사실보다 산출물로 확인합니다. 언어 기반은 작은 라이브 코딩과 타입 설계 메모, 자료구조·알고리즘은 복잡도 분석과 부하 전후 비교, Git 협업은 리뷰 코멘트와 안전한 revert 기록, OpenAPI는 schema와 error contract, 클라우드 기본은 최소 아키텍처 다이어그램과 IAM·네트워크 경계 설명으로 검증합니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-03</span><h2>학습 순서</h2></div>\n<p class=\"lede\">순서는 관심사가 아니라 의존 관계를 따릅니다. 먼저 한 기능을 끝까지 만들고, 그 다음 신뢰성과 운영성을 얹습니다.</p>\n<div class=\"flow\">\n  <span class=\"step\">제품 흐름</span><span class=\"arr\">→</span>\n  <span class=\"step\">API 계약</span><span class=\"arr\">→</span>\n  <span class=\"step\">데이터 모델</span><span class=\"arr\">→</span>\n  <span class=\"step\">구현·테스트</span><span class=\"arr\">→</span>\n  <span class=\"step hl\">배포·운영</span>\n</div>\n<table>\n<tr><th>단계</th><th>목표</th><th>읽을 문서</th><th>산출물</th></tr>\n<tr><td>1. 흐름 정의</td><td>사용자 목표와 화면 상태를 정한다</td><td>디자인 개요, 사용자 흐름, 폼</td><td>사용자 시나리오, 상태 전이표</td></tr>\n<tr><td>2. 계약 설계</td><td>API, 에러, 권한, 페이지네이션을 정한다</td><td>백엔드 개요, 프론트엔드 API 연동</td><td>OpenAPI 초안, error code 표</td></tr>\n<tr><td>3. 데이터 설계</td><td>정합성과 조회 패턴을 맞춘다</td><td>DB, JPA, 마이그레이션</td><td>ERD, migration, index 후보</td></tr>\n<tr><td>4. 구현 검증</td><td>프론트·백엔드 테스트를 나눈다</td><td>프론트엔드 테스트, 백엔드 테스트</td><td>unit, integration, E2E 최소 세트</td></tr>\n<tr><td>5. 배포 준비</td><td>설정·secret·이미지·파이프라인을 분리한다</td><td>Docker와 배포, CI/CD, 설정 관리</td><td>Dockerfile, compose, pipeline</td></tr>\n<tr><td>6. 운영 준비</td><td>로그·메트릭·알림·롤백을 확인한다</td><td>관측 가능성, DevOps, 실무 플레이북</td><td>health check, dashboard, runbook</td></tr>\n</table>\n</section>\n\n<section id=\"roadmap-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-04</span><h2>경계면 체크리스트</h2></div>\n<p class=\"lede\">풀스택 실무의 대부분의 문제는 기술 내부보다 경계면에서 납니다. 화면과 서버, 서버와 DB, 앱과 인프라 사이의 계약을 먼저 봅니다.</p>\n<table>\n<tr><th>경계</th><th>확인 질문</th><th>흔한 실패</th></tr>\n<tr><td>UI ↔ API</td><td>loading, empty, error, permission denied가 모두 정의됐는가</td><td>500만 처리하고 400/401/403/409 UX가 없음</td></tr>\n<tr><td>API ↔ DB</td><td>트랜잭션 경계와 unique 제약이 비즈니스 규칙을 보호하는가</td><td>프론트 중복 방지만 믿어 중복 데이터 생성</td></tr>\n<tr><td>Auth ↔ Browser</td><td>쿠키, SameSite, CORS, CSRF, 토큰 만료가 일관적인가</td><td>로컬은 되지만 배포 후 쿠키가 안 붙음</td></tr>\n<tr><td>Build ↔ Runtime</td><td>같은 이미지가 환경변수만 바꿔 여러 환경에서 도는가</td><td>환경별로 다른 빌드를 만들어 재현성 붕괴</td></tr>\n<tr><td>Service ↔ Network</td><td>DNS, route, firewall, TLS, health check가 맞는가</td><td>앱 문제로 보였지만 Security Group 차단</td></tr>\n<tr><td>Change ↔ Operation</td><td>배포 실패 시 rollback 또는 roll-forward 경로가 있는가</td><td>마이그레이션과 코드가 한 번에 깨짐</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">정확도 기준</span>\n<p>프론트엔드 검증, 백엔드 검증, DB 제약은 서로 대체하지 않습니다. UI 검증은 사용성을 높이고, 서버 검증은 보안과 규칙을 지키며, DB 제약은 마지막 정합성 방어선입니다. 같은 규칙이 여러 층에 반복되는 것은 중복이 아니라 방어 심도입니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-05</span><h2>캡스톤 과제</h2></div>\n<p class=\"lede\">읽은 내용을 몸에 붙이려면 작은 기능 하나를 끝까지 책임지는 과제가 필요합니다. 아래 과제를 반복하면 전체 연결이 보입니다.</p>\n<table>\n<tr><th>과제</th><th>포함해야 할 것</th><th>검증 기준</th></tr>\n<tr><td>관리자 목록·상세·수정</td><td>검색, 필터, 페이지네이션, 수정 폼, 권한</td><td>URL 상태, optimistic/pessimistic update 판단, 400/409 오류 처리</td></tr>\n<tr><td>파일 업로드 기능</td><td>용량 제한, MIME 검증, 진행률, 실패 재시도</td><td>서버 검증, 저장소 분리, 업로드 중 이탈 처리</td></tr>\n<tr><td>초대·권한 관리</td><td>초대 발송, 만료, 재발송, 역할 변경 이력</td><td>감사 로그, idempotency, 권한 테스트</td></tr>\n<tr><td>배치 작업 상태판</td><td>작업 요청, 진행 상태, 실패 사유, 재실행</td><td>polling/SSE 판단, 상태 전이, 운영 로그 연결</td></tr>\n<tr><td>배포 파이프라인</td><td>빌드, 테스트, 이미지 push, staging 배포</td><td>환경변수 분리, secret 관리, rollback 문서</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">증거 포트폴리오 규칙</span>\n<p>캡스톤은 “만들었다”가 아니라 <strong>판단과 검증이 남아 있다</strong>로 통과합니다. 각 과제는 코드 저장소와 함께 아래 산출물을 같은 버전으로 묶어 제출합니다.</p>\n</div>\n<table>\n<tr><th>산출물</th><th>포함 내용</th><th>통과 기준</th></tr>\n<tr><td>문제 명세</td><td>사용자, 업무 목표, 제약, 데이터 규모, 비기능 목표</td><td>무엇을 하지 않을지도 적혀 있고 성공/실패 기준이 숫자나 관찰 가능한 상태로 표현된다</td></tr>\n<tr><td>API 계약</td><td>OpenAPI, 요청·응답 schema, error contract, 권한, 멱등성 key</td><td>400/401/403/404/409/429/5xx가 UI 상태와 연결되고 breaking change 정책이 있다</td></tr>\n<tr><td>데이터 모델</td><td>ERD, migration, index, unique 제약, 상태 전이, 감사 로그</td><td>동시성 충돌과 rollback 가능한 schema 변경 순서가 설명된다</td></tr>\n<tr><td>ADR</td><td>선택지 2개 이상, 결정, 포기한 것, 되돌릴 조건</td><td>현재 규모에서 왜 충분한지와 어떤 신호가 보이면 바꿀지 적혀 있다</td></tr>\n<tr><td>테스트 계획</td><td>unit, integration, contract, E2E, 접근성, 실패 주입</td><td>해피패스보다 권한, timeout, retry, 중복 요청, 부분 실패를 우선 검증한다</td></tr>\n<tr><td>성능 증거</td><td>baseline, p95/p99, 실행계획, bundle 또는 렌더링 지표, 개선 전후</td><td>병목 위치와 개선 근거가 수치로 남고 재현 명령이 함께 있다</td></tr>\n<tr><td>보안·위협 모델</td><td>신뢰 경계, STRIDE, abuse case, secret, PII, rate limit</td><td>서버 권한 검증과 입력 검증을 전제로 공격 경로와 방어선을 설명한다</td></tr>\n<tr><td>관측·런북</td><td>로그 필드, traceId, dashboard, alert, health check, 운영 절차</td><td>장애를 감지할 신호, 담당자가 볼 화면, 첫 15분 조치가 적혀 있다</td></tr>\n<tr><td>롤백·포스트모템</td><td>rollback/roll-forward, 데이터 복구, RTO/RPO, 재발 방지 액션</td><td>배포 실패와 운영 장애를 각각 복구해 본 기록이 남아 있다</td></tr>\n</table>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>CAP-01</b><span>problem</span></div><div class=\"g-def\">문제 명세는 요구사항 목록이 아니라 결정 문서의 시작점입니다. 사용자 영향, 제외 범위, 성공 지표, 모르는 것을 먼저 분리합니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>CAP-02</b><span>contract</span></div><div class=\"g-def\">API 계약과 데이터 모델은 같이 리뷰합니다. 응답 필드 하나가 추가될 때 UI 상태, 캐시, migration, 권한까지 같이 바뀌는지 확인합니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>CAP-03</b><span>operation</span></div><div class=\"g-def\">성능, 보안, 관측, 롤백은 구현 뒤 장식이 아닙니다. 설계 초안부터 어떤 증거를 남길지 정해야 나중에 운영 가능한 기능이 됩니다.</div></div>\n</div>\n</section>\n\n<section id=\"roadmap-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-06</span><h2>품질 기준</h2></div>\n<p class=\"lede\">풀스택 기능은 “동작한다”에서 끝나지 않습니다. 아래 기준을 PR 체크리스트처럼 사용합니다.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>계약</b><span>contract</span></div><div class=\"g-def\">요청·응답·에러·권한·페이지네이션이 문서화되어 있고, breaking change가 관리됩니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>정합성</b><span>consistency</span></div><div class=\"g-def\">트랜잭션, unique 제약, 멱등성, 동시성 충돌 처리가 설계되어 있습니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>사용성</b><span>usability</span></div><div class=\"g-def\">loading, empty, error, disabled, success 상태가 사용자 행동과 연결됩니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>보안</b><span>security</span></div><div class=\"g-def\">인증과 인가가 분리되어 있고, 서버가 모든 입력과 권한을 최종 검증합니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>운영성</b><span>operability</span></div><div class=\"g-def\">로그, 메트릭, traceId, health check, rollback/runbook이 준비되어 있습니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>성능</b><span>performance</span></div><div class=\"g-def\">초기 로드, API latency, 쿼리 실행계획, p95/p99 지연을 측정하고 병목을 설명합니다.</div></div>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">읽는 방법</span>\n<p>각 영역 문서를 순서대로 완독하는 것보다, 하나의 기능을 잡고 이 기준을 통과시키는 방식이 빠릅니다. 부족한 기준이 보이면 해당 핸드북으로 들어가 깊이를 보강합니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-07</span><h2>고급 개발자 루브릭</h2></div>\n<p class=\"lede\">고급 개발자는 더 많은 기술명을 아는 사람이 아니라, 불확실한 조건에서 시스템을 안전하게 바꾸고 그 결정을 설명할 수 있는 사람입니다. 아래 기준은 각 장을 읽은 뒤 스스로 점검할 최소 루브릭입니다.</p>\n<table>\n<tr><th>역량</th><th>통과 기준</th><th>증거</th></tr>\n<tr><td>문제 정의</td><td>요구사항, 제약, 비기능 목표, 모르는 것을 분리한다</td><td>기능 명세, SLO, 데이터 규모, 권한 범위가 먼저 적힌다</td></tr>\n<tr><td>설계 판단</td><td>선택지와 포기한 것을 함께 설명한다</td><td>ADR, trade-off table, rollback plan이 남는다</td></tr>\n<tr><td>구현 품질</td><td>해피패스와 실패 경로를 함께 구현한다</td><td>400/401/403/409/5xx, timeout, retry, idempotency 테스트가 있다</td></tr>\n<tr><td>운영 책임</td><td>배포 후 문제를 감지하고 완화할 수 있다</td><td>로그, 메트릭, traceId, dashboard, runbook, alert 기준이 있다</td></tr>\n<tr><td>리뷰 역량</td><td>코드 스타일보다 위험과 계약을 먼저 본다</td><td>동시성, 보안, migration, 성능, 접근성, 장애 모드가 리뷰된다</td></tr>\n<tr><td>학습 전이</td><td>한 영역의 원리를 다른 영역에 옮겨 적용한다</td><td>UI 상태와 DB 상태 전이, API 계약과 컴포넌트 API를 연결해 설명한다</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">핵심 기준</span>\n<p>“이 기능을 만들 수 있는가”보다 <strong>“이 기능이 실패할 때 어디서 감지되고, 어떻게 제한되며, 어떻게 복구되는가”</strong>를 답할 수 있어야 합니다. 이 질문에 답하지 못하면 아직 운영 가능한 설계가 아닙니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-08</span><h2>실전 훈련 루프</h2></div>\n<p class=\"lede\">핸드북은 읽는 것만으로 완성되지 않습니다. 하나의 capstone을 선택해 설계, 구현, 운영, 회고까지 반복해야 지식이 판단으로 바뀝니다.</p>\n<table>\n<tr><th>훈련</th><th>할 일</th><th>검증 질문</th></tr>\n<tr><td>설계 리뷰</td><td>ADR 1장을 작성하고 대안을 2개 이상 비교</td><td>왜 이 구조가 현재 규모와 팀에 맞는가</td></tr>\n<tr><td>성능 리허설</td><td>목록/검색/API에 부하를 주고 p95, p99를 기록</td><td>병목이 DB, 네트워크, 렌더링, GC 중 어디인가</td></tr>\n<tr><td>장애 주입</td><td>DB 지연, 외부 API timeout, queue 적체, chunk 404를 일부러 만든다</td><td>사용자 영향이 제한되고 알림이 울리는가</td></tr>\n<tr><td>보안 점검</td><td>STRIDE 기준으로 신뢰 경계와 abuse case를 적는다</td><td>인가 누락, XSS, CSRF, secret 노출을 어떻게 막는가</td></tr>\n<tr><td>복구 훈련</td><td>rollback, restore drill, hotfix 절차를 실제로 실행</td><td>RTO/RPO 안에 복구 가능한가</td></tr>\n<tr><td>포스트모템</td><td>원인보다 재발 방지 액션을 남긴다</td><td>같은 실패가 다시 와도 더 빨리 감지·완화되는가</td></tr>\n</table>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>LOOP-01</b><span>baseline</span></div><div class=\"g-def\">구현 전에 문제 명세, API 계약, 데이터 모델, ADR 초안을 먼저 만듭니다. 이때 성능 목표, 보안 경계, 관측 신호, rollback 조건도 빈칸으로 남기지 않습니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>LOOP-02</b><span>evidence</span></div><div class=\"g-def\">구현 중에는 테스트 계획과 성능 증거를 계속 갱신합니다. 실패한 테스트, 느린 쿼리, 취소한 설계안도 senior-level 판단 근거로 남깁니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>LOOP-03</b><span>operation</span></div><div class=\"g-def\">배포 전에는 threat model, dashboard, alert, runbook, rollback drill을 묶어 리뷰합니다. 기능 설명보다 “실패하면 어떻게 제한하고 복구하는가”가 먼저 답해야 합니다.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>LOOP-04</b><span>review</span></div><div class=\"g-def\">배포 뒤에는 포스트모템 형식으로 학습을 닫습니다. 실제 지표, 놓친 위험, 다음 capstone에서 바꿀 정책을 한 페이지에 남깁니다.</div></div>\n</div>\n<table>\n<tr><th>리뷰 게이트</th><th>질문</th><th>필수 증거</th></tr>\n<tr><td>설계 승인</td><td>현재 문제에 충분하고 나중에 바꿀 수 있는가</td><td>문제 명세, API 계약, 데이터 모델, ADR</td></tr>\n<tr><td>구현 승인</td><td>성공 경로와 실패 경로가 모두 검증됐는가</td><td>테스트 계획, contract test, 권한·동시성·에러 테스트 결과</td></tr>\n<tr><td>출시 승인</td><td>사용자 영향과 운영 신호를 볼 수 있는가</td><td>성능 측정, threat model, dashboard, alert, runbook</td></tr>\n<tr><td>복구 승인</td><td>잘못된 배포와 데이터 문제를 제한할 수 있는가</td><td>rollback 기록, restore drill, hotfix 절차, postmortem</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">시니어급 학습 방식</span>\n<p>문서를 한 번에 끝까지 읽는 것보다, capstone 하나를 잡고 이 루프를 반복하세요. 같은 기능을 성능, 보안, 접근성, 배포, 장애 대응 관점으로 다시 보는 과정이 고급 개발자의 사고 훈련입니다.</p>\n</div>\n</section>\n\n<section id=\"roadmap-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-09</span><h2>실전 경험 시뮬레이터</h2></div>\n<p class=\"lede\">회사 경험을 완전히 대체할 수는 없지만, <strong>불완전한 요구사항, 시간 압박, 장애, 리뷰 반박, 운영 증거</strong>를 강제로 넣으면 실제 경험과 가까운 압력을 만들 수 있습니다. 아래 프로그램은 혼자 또는 스터디에서 하나의 캡스톤을 실제 서비스처럼 운영해 보는 훈련입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">EXPERIENCE SIMULATOR</span>\n목표: 기능 하나를 설계, 구현, 출시, 장애 대응, 회고까지 끝낸다<br>\n기간: 6주 또는 6회차 반복<br>\n규칙: 매주 새로운 사건 카드를 1개 추가하고 기존 설계를 방어한다<br>\n제출: 코드보다 판단 증거를 우선 제출한다<br>\n평가: 동작 여부, 실패 대응, 설명 가능성, 복구 가능성으로 채점한다\n</div>\n<table>\n<tr><th>주차</th><th>상황 카드</th><th>필수 산출물</th><th>통과 기준</th></tr>\n<tr><td>Week 1 Discovery</td><td>PM이 “관리자에서 고객 상태를 수정하고 이력을 보고 싶다”고만 요청한다.</td><td>문제 명세, 사용자 흐름, 비목표, 성공 지표, unknown list</td><td>요구사항을 그대로 구현하지 않고 데이터 규모, 권한, 감사, 실패 상태를 질문으로 분리한다.</td></tr>\n<tr><td>Week 2 Design Review</td><td>리뷰어가 “왜 단순 CRUD가 아니라 상태 전이와 감사 로그가 필요한가?”라고 반박한다.</td><td>API 계약, ERD, 상태 전이표, ADR, rollback 가능한 migration 순서</td><td>선택지 2개 이상을 비교하고 지금 선택을 바꿔야 하는 조건을 적는다.</td></tr>\n<tr><td>Week 3 Implementation</td><td>기존 코드에 유사 기능이 있지만 권한 체크가 controller에 흩어져 있다.</td><td>PR 설명, 테스트 계획, 권한 negative test, contract test, migration diff</td><td>동작 구현보다 객체 단위 인가, 중복 요청, 409 충돌, 부분 실패 테스트가 먼저 보인다.</td></tr>\n<tr><td>Week 4 Game Day</td><td>출시 직후 p95가 3배 증가하고 일부 관리자가 403을 받는다.</td><td>incident timeline, dashboard screenshot, slow query evidence, rollback/forward-fix 판단</td><td>원인을 단정하기 전에 사용자 영향, 최근 변경, 계층별 증거, 완화책, 종료 조건을 순서대로 기록한다.</td></tr>\n<tr><td>Week 5 Security Challenge</td><td>테스터가 다른 tenant의 id를 넣어 일부 export job 결과를 볼 수 있다고 보고한다.</td><td>threat model, IDOR 재현 절차, 영향 범위, hotfix, audit query, 고객 영향 판단</td><td>controller hotfix만 하지 않고 worker, cache, export, audit까지 같은 정책이 적용되는지 검증한다.</td></tr>\n<tr><td>Week 6 Postmortem</td><td>팀 리더가 “다음번에는 무엇을 자동화하거나 기준화할 것인가?”를 묻는다.</td><td>postmortem, action item owner/date, runbook update, eval checklist, 다음 capstone 개선안</td><td>개인 반성이 아니라 재발 방지 시스템 변경으로 닫는다.</td></tr>\n</table>\n<h3><span class=\"h3-tag\">SIM</span>Senior Simulation Scorecard</h3>\n<table>\n<tr><th>항목</th><th>0점</th><th>1점</th><th>2점</th></tr>\n<tr><td>문제 구조화</td><td>요구를 기능 목록으로만 옮김</td><td>주요 요구와 비목표는 분리함</td><td>사용자 영향, 제약, unknown, 성공 지표까지 분리함</td></tr>\n<tr><td>설계 방어</td><td>선택 이유가 취향이나 익숙함</td><td>대안은 있으나 포기한 비용이 약함</td><td>대안, trade-off, 되돌릴 조건, 운영 비용이 연결됨</td></tr>\n<tr><td>구현 검증</td><td>happy path와 snapshot 중심</td><td>일부 실패 경로를 테스트함</td><td>권한, 동시성, 마이그레이션, 성능, 회귀를 증거로 검증함</td></tr>\n<tr><td>운영 대응</td><td>로그를 보고 추측함</td><td>dashboard와 runbook은 있으나 판단 순서가 약함</td><td>영향 범위, 최근 변경, 완화, 검증, 종료 조건이 timeline에 남음</td></tr>\n<tr><td>리뷰 커뮤니케이션</td><td>반박을 방어적으로 처리함</td><td>질문에 답하지만 문서 갱신이 늦음</td><td>리뷰 질문을 ADR, 테스트, runbook, known risk에 반영함</td></tr>\n<tr><td>학습 전이</td><td>한 번 만든 기능으로 끝냄</td><td>회고는 남기지만 다음 과제와 약하게 연결됨</td><td>다음 capstone의 기준, 템플릿, 자동화 항목으로 전환함</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">경험 대체의 한계와 보완</span>\n<p>이 시뮬레이터는 실제 사용자, 조직 정치, 레거시 부채, 온콜 피로를 완전히 재현하지 못합니다. 대신 혼자서도 <strong>불확실성 속에서 결정하고, 증거로 방어하고, 실패를 복구하는 루프</strong>를 반복하게 만듭니다. 이 루프를 3개 이상의 서로 다른 capstone에 적용하면 단순 지식 숙지보다 훨씬 시니어에 가까운 판단 근육을 만들 수 있습니다.</p>\n</div>\n</section>\n\n<footer>\nFULLSTACK GROWTH ROADMAP · V1 · 2026-06<br>\nPRINCIPLE : 기능을 화면, 계약, 데이터, 배포, 운영 신호까지 연결해 책임진다\n</footer>\n\n<section id=\"doc-faq\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>개발자 FAQ·트러블슈팅</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : DEV-FAQ-V1</span>\n    <span>SCOPE : FAQ · DEBUGGING · AI CODE REVIEW</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>개발자 FAQ·트러블슈팅<br>실무 가이드</h1>\n  <p class=\"hero-sub\">개발자가 가장 자주 묻는 질문은 대개 기술명이 아니라 <strong>증상</strong>으로 시작합니다. 이 문서는 \"왜 로컬은 되는데 배포하면 안 되지?\", \"어떤 로그를 봐야 하지?\", \"AI가 만든 코드를 믿어도 되나?\" 같은 질문을 <strong>증상 → 가설 → 증거 → 수정 → 예방</strong>의 실행 순서로 바꾸는 triage hub입니다.</p>\n  <div class=\"hero-meta\">METHOD : symptoms → hypotheses → evidence → fix → prevention → institutional memory<br>COMPILED : 2026-06 · BASIS : developer Q&amp;A patterns, survey reports, incident practice</div>\n</header>\n\n<section id=\"faq-ch15\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-15</span><h2>증상 기반 빠른 진입</h2></div>\n<p class=\"lede\">실무에서 질문은 \"어느 장을 읽어야 하나요?\"가 아니라 \"지금 이 증상이 무엇을 뜻하나요?\"로 들어옵니다. 아래 표는 증상에서 바로 확인 순서로 들어가기 위한 routing table입니다.</p>\n<table>\n<tr><th>증상</th><th>먼저 갈 장</th><th>첫 확인</th><th>다음 액션</th></tr>\n<tr><td>로컬은 되는데 CI에서만 실패</td><td>FAQ-02, FAQ-03, FAQ-07</td><td>런타임 버전, lockfile, OS/arch, install 명령</td><td>깨끗한 checkout과 CI 이미지로 재현</td></tr>\n<tr><td>배포 후 로그인만 깨짐</td><td>FAQ-04, FAQ-13</td><td>Set-Cookie, SameSite, Secure, CORS credential</td><td>브라우저 저장 여부와 다음 요청 Cookie header 비교</td></tr>\n<tr><td>특정 고객 데이터만 느림</td><td>FAQ-06, FAQ-05, FAQ-12</td><td>tenant별 row 수, query plan, payload size</td><td>p95/p99를 tenant와 route별로 나눠 본다</td></tr>\n<tr><td>간헐적으로 중복 주문·초대가 생김</td><td>FAQ-11, FAQ-05</td><td>idempotency key, unique constraint, retry 로그</td><td>동시 요청 테스트와 상태 전이표 작성</td></tr>\n<tr><td>테스트가 다시 돌리면 통과</td><td>FAQ-07</td><td>시간, 순서, 외부 의존성, 병렬성</td><td>단독/전체 실행 차이와 seed cleanup 확인</td></tr>\n<tr><td>PR 리뷰가 계속 지연</td><td>FAQ-08, FAQ-14</td><td>diff 크기, generated file, migration, 테스트 증거</td><td>리팩터/기능/생성물/테스트로 PR 분리</td></tr>\n<tr><td>장애 중 원인을 못 좁힘</td><td>FAQ-10, FAQ-12</td><td>영향 범위, 최근 변경, traceId, dashboard</td><td>완화와 진단을 분리하고 status update 주기 고정</td></tr>\n<tr><td>AI가 만든 코드가 그럴듯하지만 불안함</td><td>FAQ-09, FAQ-13, FAQ-17</td><td>권한, 데이터 삭제, secret, dependency, test gap</td><td>risk tier와 owner review 기준으로 승인 범위 제한</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">FIRST 15 MINUTES — 문제를 받자마자</span>\n1. 사용자 영향과 재현 조건을 한 줄로 고정<br>\n2. 마지막 정상 시점과 최근 변경을 확인<br>\n3. 요청 ID, traceId, release SHA, 환경 이름을 묶음<br>\n4. 증상이 사용자 영향이면 완화부터, 개발 환경 문제면 재현부터<br>\n5. 가설은 최대 3개만 열고, 각 가설마다 증거 하나를 요구\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">진입 규칙</span>\n<p>처음 15분의 목표는 해결이 아니라 <strong>범위 축소</strong>입니다. 앱 문제인지, 설정 문제인지, 데이터 문제인지, 외부 의존성 문제인지 나누기 전에는 코드 수정부터 하지 않습니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-01</span><h2>질문을 문제 정의로 바꾸기</h2></div>\n<p class=\"lede\">초보자와 숙련자의 차이는 답을 아는 양보다 <em>질문을 재현 가능한 문제로 바꾸는 속도</em>에서 크게 납니다. 질문이 \"안 돼요\"에 머물면 도와주는 사람도 추측만 하게 됩니다.</p>\n<table>\n<tr><th>나쁜 질문</th><th>좋은 질문</th><th>왜 좋은가</th></tr>\n<tr><td>로그인이 안 됩니다</td><td>Chrome에서 로그인 POST는 200인데 다음 API에 쿠키가 안 붙습니다. SameSite, Secure, Domain, CORS credential 설정을 비교했습니다.</td><td>HTTP 계층과 쿠키 계층으로 범위를 좁힘</td></tr>\n<tr><td>빌드가 깨져요</td><td>로컬 Node 20에서는 통과하지만 CI Node 18에서 optional dependency 로딩이 실패합니다. lockfile과 native package 차이를 의심합니다.</td><td>환경 차이와 가설이 있음</td></tr>\n<tr><td>DB가 느립니다</td><td>주문 목록 p95가 200ms에서 2.4s로 늘었고, EXPLAIN에서 created_at 정렬 후 filesort가 발생합니다.</td><td>증상, 지표, 실행 계획이 있음</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">MRE TEMPLATE — 도움 요청 전 최소 정보</span>\n증상: 무엇이 기대와 다르게 보이는가<br>\n재현: 어떤 입력/명령/브라우저/환경에서 100% 또는 간헐적으로 나는가<br>\n범위: 마지막 정상 시점, 최근 변경, 영향 사용자/기능<br>\n증거: 에러 전문, 로그 앞뒤 30줄, 네트워크 요청, 실행 계획, 스크린샷<br>\n시도: 이미 해본 것과 배제한 가설<br>\n요청: 무엇을 판단해 달라는 것인가\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">실무 기준</span>\n<p>질문은 \"정답을 달라\"가 아니라 \"내 가설이 맞는지 검토해 달라\"에 가까워야 합니다. 재현 조건, 마지막 정상 시점, 최근 변경, 관측 증거가 있으면 대부분의 문제는 질문하는 과정에서 절반 이상 좁혀집니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-02</span><h2>로컬은 되는데 CI·운영은 실패</h2></div>\n<p class=\"lede\">가장 흔한 질문 중 하나입니다. 이 문제는 거의 항상 <strong>환경 차이</strong>, <strong>숨은 상태</strong>, <strong>외부 의존성</strong>, <strong>권한</strong> 중 하나입니다.</p>\n<table>\n<tr><th>분류</th><th>확인할 것</th><th>대표 증상</th></tr>\n<tr><td>런타임 버전</td><td>Node/JDK/Python/Gradle/npm/pnpm 버전, OS, CPU 아키텍처</td><td>로컬은 통과, CI에서 native binding 또는 syntax 오류</td></tr>\n<tr><td>lockfile</td><td>lockfile이 커밋됐는지, CI가 frozen install을 쓰는지</td><td>팀원마다 다른 transitive dependency 설치</td></tr>\n<tr><td>환경변수</td><td>필수 env 누락, build-time env와 runtime env 구분</td><td>배포 후 undefined, API base URL 오작동</td></tr>\n<tr><td>파일시스템</td><td>대소문자 구분, 상대 경로, working directory</td><td>macOS는 되는데 Linux CI에서 import 실패</td></tr>\n<tr><td>네트워크·권한</td><td>private registry, DB, secret store, firewall 접근 권한</td><td>CI에서만 패키지 install 또는 migration 실패</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">DIFF COMMANDS — 환경 차이 먼저 고정</span>\nnode -v && npm -v && java -version && ./gradlew -v<br>\npwd && uname -a && env <span class=\"dim\">|</span> sort<br>\nnpm ci <span class=\"dim\"># 또는 pnpm install --frozen-lockfile</span><br>\ngit status --short <span class=\"dim\"># 먼저 변경 상태 확인</span><br>\ngit diff &gt; /tmp/wip.patch <span class=\"dim\"># 커밋 전 변경 백업</span><br>\ngit clean -xfdn <span class=\"dim\"># dry-run: 삭제될 파일만 미리 보기</span><br>\ngit clean -xfd <span class=\"dim\"># 정말 지워도 되는 대상임을 확인한 뒤에만</span>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">파괴적 명령 주의</span>\n<p><code>git clean -xfd</code>는 untracked 파일과 ignored 파일까지 삭제할 수 있습니다. 로컬 DB dump, 임시 문서, 개인 설정, 생성 산출물이 날아갈 수 있으므로 항상 <code>git clean -xfdn</code>으로 대상 목록을 먼저 보고, 필요한 파일을 백업한 뒤 실행합니다. 의존성만 의심된다면 <code>node_modules</code>, build cache처럼 명확한 대상만 제거하는 쪽이 더 안전합니다.</p>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">예방 규칙</span>\n<p>팀 프로젝트는 \"내 PC에서 됨\"을 기준으로 삼지 않습니다. 런타임 버전은 <code>.nvmrc</code>, <code>.tool-versions</code>, <code>mise.toml</code>처럼 파일로 고정하고, CI는 lockfile 기반 설치만 허용합니다. 로컬 성공보다 깨끗한 checkout에서 재현되는지가 더 강한 증거입니다.</p>\n</div>\n<h3><span class=\"h3-tag\">DECISION TREE</span>어디서 갈라졌는가</h3>\n<table>\n<tr><th>질문</th><th>YES면</th><th>NO면</th></tr>\n<tr><td>깨끗한 checkout에서 재현되는가?</td><td>프로젝트 설정 또는 코드 문제로 본다</td><td>로컬 캐시, 전역 도구, 숨은 파일, IDE 설정을 의심한다</td></tr>\n<tr><td>같은 런타임 버전인가?</td><td>lockfile, env, OS 차이로 이동</td><td>버전 파일과 CI 이미지부터 맞춘다</td></tr>\n<tr><td>빌드 artifact가 환경마다 같은가?</td><td>runtime config와 외부 의존성 확인</td><td>환경별 빌드가 섞였는지, build-time env가 박혔는지 확인</td></tr>\n<tr><td>서버 로그에 요청이 도달하는가?</td><td>앱, auth, DB, 외부 API 계층 확인</td><td>DNS, route, firewall, TLS, CORS preflight 확인</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">증거 묶음</span>\n<p>이슈에 올릴 때는 실패 로그만 붙이지 말고 성공 환경과 실패 환경의 차이를 표로 붙입니다. 런타임 버전, OS/arch, install 명령, lockfile hash, env key 목록, 최근 배포 SHA, 실패 명령을 같이 보면 리뷰어가 추측을 줄일 수 있습니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-03</span><h2>빌드·의존성·버전 충돌</h2></div>\n<p class=\"lede\">의존성 문제는 \"패키지 하나가 안 깔림\"처럼 보이지만 실제로는 lockfile, transitive dependency, peer dependency, native package, repository 권한 문제가 섞여 있습니다.</p>\n<table>\n<tr><th>질문</th><th>먼저 볼 증거</th><th>처리 원칙</th></tr>\n<tr><td>왜 npm install만 하면 계속 바뀌나요?</td><td><code>package-lock.json</code>, package manager 버전, install 명령</td><td>CI와 로컬 설치 명령을 통일하고 lockfile 변경을 리뷰한다</td></tr>\n<tr><td>peer dependency 경고를 무시해도 되나요?</td><td>경고 대상 패키지, runtime 오류 여부, major version 차이</td><td>무시는 임시 조치다. 실제 호환 matrix를 확인하고 ADR에 남긴다</td></tr>\n<tr><td>Gradle이 갑자기 느려졌습니다</td><td>daemon 상태, dependency resolution, test task, build cache</td><td>clean build와 incremental build를 분리해 측정한다</td></tr>\n<tr><td>native module이 CI에서만 실패합니다</td><td>OS/arch, libc, optional dependency, postinstall 로그</td><td>런타임 이미지와 빌드 이미지를 맞추고 optional dependency 누락을 확인한다</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">DEPENDENCY TRIAGE</span>\nnpm ls &lt;package&gt; <span class=\"dim\"># 어떤 경로로 들어왔는지</span><br>\nnpm explain &lt;package&gt;<br>\n./gradlew dependencies --configuration runtimeClasspath<br>\n./gradlew dependencyInsight --dependency &lt;module&gt;\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">금지 패턴</span>\n<p><code>--force</code>, <code>--legacy-peer-deps</code>, lockfile 삭제, Gradle cache 삭제는 원인 분석이 아니라 상태 초기화입니다. 임시로 써야 한다면 \"왜 필요한지\", \"언제 제거할지\", \"어떤 호환성을 포기했는지\"를 PR에 남겨야 합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">LOCKFILE REVIEW</span>의존성 PR에서 볼 것</h3>\n<table>\n<tr><th>변경</th><th>리뷰 포인트</th><th>질문</th></tr>\n<tr><td>direct dependency 추가</td><td>기능 필요성, 유지보수 상태, license, bundle/runtime 영향</td><td>표준 API나 기존 패키지로 충분하지 않은가</td></tr>\n<tr><td>transitive 대량 변경</td><td>package manager 버전 차이 또는 install 방식 차이</td><td>코드 변경 없이 lockfile만 크게 바뀐 이유가 무엇인가</td></tr>\n<tr><td>major version upgrade</td><td>breaking change, migration guide, rollback 계획</td><td>호환성 테스트와 canary 경로가 있는가</td></tr>\n<tr><td>native dependency</td><td>OS/arch, Docker base image, optional dependency 설치</td><td>CI와 운영 이미지에서 같은 binary가 로드되는가</td></tr>\n<tr><td>보안 패치</td><td>취약점 도달 가능성, patch/minor/major 선택</td><td>업데이트 후 regression test 범위가 충분한가</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-04</span><h2>환경변수·쿠키·CORS·시크릿</h2></div>\n<p class=\"lede\">배포 후 로그인, API 호출, redirect가 깨지는 문제는 대부분 설정 경계에서 발생합니다. 특히 build-time env와 runtime env, 브라우저 쿠키 정책, CORS credential 설정이 자주 섞입니다.</p>\n<table>\n<tr><th>증상</th><th>가능한 원인</th><th>확인</th></tr>\n<tr><td>프론트에서 API base URL이 이상함</td><td>빌드 시점 env가 번들에 박힘</td><td>빌드 로그와 배포 artifact의 env 주입 방식 확인</td></tr>\n<tr><td>로그인은 200인데 세션 유지 안 됨</td><td>SameSite, Secure, Domain, path, credential 누락</td><td>DevTools Application 탭과 Set-Cookie header 비교</td></tr>\n<tr><td>CORS 에러가 브라우저에서만 남</td><td>서버 CORS, preflight, allowed headers/methods 불일치</td><td>OPTIONS 응답과 실제 요청 header 확인</td></tr>\n<tr><td>운영 secret이 undefined</td><td>secret store 키 누락, 배포 대상 namespace 오류</td><td>CI/CD variable scope와 runtime env dump의 redacted 목록 확인</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">CORS 오해</span>\n<p>CORS는 서버 간 통신 문제가 아니라 브라우저 보안 정책입니다. curl은 되는데 브라우저가 막는다면 네트워크가 아니라 Origin, credential, preflight 응답을 봐야 합니다. 반대로 서버 로그에 요청 자체가 없다면 DNS, route, firewall, TLS를 먼저 봅니다.</p>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">시크릿 대응</span>\n<p>시크릿이 로그나 git에 노출되면 \"삭제\"가 아니라 <strong>폐기와 재발급</strong>이 먼저입니다. 노출된 값은 이미 복사됐다고 가정하고 rotate한 뒤, 히스토리 정리와 secret scanning을 진행합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">COOKIE DEBUG</span>세션 쿠키가 안 붙을 때</h3>\n<table>\n<tr><th>확인</th><th>의미</th><th>흔한 수정</th></tr>\n<tr><td><code>Set-Cookie</code>가 응답에 있는가</td><td>서버가 쿠키를 발급했는지</td><td>인증 서버 응답, proxy header, HTTPS 종료 지점 확인</td></tr>\n<tr><td>브라우저 Application 탭에 저장됐는가</td><td>브라우저 정책에 의해 거부됐는지</td><td><code>Secure</code>, <code>SameSite=None</code>, Domain/Path 조정</td></tr>\n<tr><td>다음 요청에 Cookie header가 붙는가</td><td>credential 포함 여부</td><td>fetch/axios <code>credentials</code>, 서버 <code>Access-Control-Allow-Credentials</code></td></tr>\n<tr><td>preflight가 통과하는가</td><td>실제 요청 전 OPTIONS에서 막히는지</td><td>allowed origin/header/method를 실제 요청과 일치</td></tr>\n<tr><td>proxy가 header를 제거하지 않는가</td><td>LB, CDN, gateway가 쿠키를 바꾸는지</td><td>forwarded proto, cookie allowlist, cache policy 확인</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-05</span><h2>DB 마이그레이션·락·시딩</h2></div>\n<p class=\"lede\">DB 문제는 로컬에서 쉽게 고치려고 drop/reset을 반복하다가 운영 사고로 이어질 수 있습니다. 로컬 재생성과 운영 변경은 완전히 다른 절차입니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">스코프</span>\n<p>이 장의 명령과 예시는 PostgreSQL 기준입니다. <code>EXPLAIN (ANALYZE, BUFFERS)</code>, <code>pg_stat_activity</code>, <code>pg_locks</code>, <code>NOT VALID</code>, concurrent index 같은 표현은 PostgreSQL 기능입니다. MySQL, MariaDB, SQL Server, Oracle에서는 같은 원칙을 적용하되 실행 계획, lock 조회, online DDL 문법을 해당 DB 기준으로 바꿔야 합니다.</p>\n</div>\n<table>\n<tr><th>질문</th><th>실무 답변</th><th>위험 신호</th></tr>\n<tr><td>컬럼 하나 추가인데 왜 조심해야 하나요?</td><td>테이블 크기, default, NOT NULL, index 생성 방식에 따라 lock과 rewrite가 생긴다</td><td>운영 대용량 테이블에 한 번에 NOT NULL + default + backfill</td></tr>\n<tr><td>마이그레이션이 실패했는데 수정해도 되나요?</td><td>이미 공유/운영에 적용된 migration은 수정하지 말고 새 migration으로 보정한다</td><td>기존 migration 파일을 고쳐 팀원 DB와 history가 갈라짐</td></tr>\n<tr><td>시더는 왜 멱등이어야 하나요?</td><td>여러 번 실행해도 같은 상태가 되어야 로컬 복구와 테스트가 안정적이다</td><td>재실행할 때마다 중복 row 또는 다른 ID 생성</td></tr>\n<tr><td>느린 쿼리는 인덱스만 추가하면 되나요?</td><td>실행 계획, cardinality, 정렬, pagination, lock 비용을 같이 본다</td><td>EXPLAIN 없이 감으로 index 추가</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">POSTGRES FIRST LOOK</span>\nEXPLAIN (ANALYZE, BUFFERS) SELECT ...;<br>\nSELECT * FROM pg_stat_activity WHERE state &lt;&gt; 'idle';<br>\nSELECT * FROM pg_locks WHERE NOT granted;<br>\nSELECT relname, n_live_tup, n_dead_tup FROM pg_stat_user_tables;\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">운영 변경 원칙</span>\n<p>운영 DB 변경은 expand-contract로 쪼갭니다. 먼저 nullable 컬럼과 호환 코드, 그 다음 backfill, 검증, 제약 강화, 마지막으로 옛 코드/컬럼 제거 순서입니다. \"한 번에 끝내기\"보다 \"중간 상태도 서비스 가능한가\"가 중요합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">ZERO DOWNTIME</span>운영 마이그레이션 질문</h3>\n<table>\n<tr><th>변경</th><th>안전한 순서</th><th>검증</th></tr>\n<tr><td>새 컬럼 추가</td><td>nullable 추가 → 코드 배포 → backfill → 제약 강화</td><td>null 비율, write path, rollback 호환성</td></tr>\n<tr><td>컬럼명 변경</td><td>새 컬럼 추가 → dual write/read → backfill → read 전환 → 옛 컬럼 제거</td><td>양쪽 값 비교, 배포 순서, consumer 영향</td></tr>\n<tr><td>인덱스 추가</td><td>가능하면 concurrent 생성 → 실행 계획 확인 → query hint 없이 반영</td><td>lock wait, index size, write latency</td></tr>\n<tr><td>NOT NULL 강화</td><td>데이터 정리 → NOT VALID check → validate → NOT NULL</td><td>누락 row 없음, validation 시간</td></tr>\n<tr><td>enum/status 추가</td><td>producer/consumer가 unknown 값을 견디는지 먼저 확인</td><td>옛 앱 버전이 새 값을 받았을 때의 동작</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-06</span><h2>\"느려요\" 성능 triage</h2></div>\n<p class=\"lede\">성능 질문은 먼저 병목 위치를 찾아야 합니다. 프론트, 네트워크, API, DB, 외부 서비스, 런타임 자원 중 어디인지 모르면 최적화가 추측이 됩니다.</p>\n<table>\n<tr><th>계층</th><th>먼저 볼 지표</th><th>흔한 원인</th></tr>\n<tr><td>브라우저</td><td>LCP, INP, CLS, long task, bundle size</td><td>큰 이미지, 불필요한 렌더, main thread blocking</td></tr>\n<tr><td>네트워크</td><td>DNS, TCP, TLS, TTFB, payload size</td><td>멀리 있는 리전, 캐시 부재, 압축 누락</td></tr>\n<tr><td>API</td><td>p50/p95/p99, error rate, queue time</td><td>N+1, 외부 API 대기, thread pool 고갈</td></tr>\n<tr><td>DB</td><td>query plan, buffer hit, lock wait, slow query</td><td>인덱스 부재, 잘못된 pagination, 통계 stale</td></tr>\n<tr><td>런타임</td><td>CPU, memory, GC, event loop lag</td><td>OOM 직전 GC, blocking I/O, 과도한 serialization</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">측정 순서</span>\n<p>평균 응답 시간은 착시를 만듭니다. 사용자는 p95/p99 지연을 체감합니다. \"느림\"을 받으면 먼저 느린 사용자의 요청 ID, 시간대, route, payload, 지역, 브라우저/기기, 배포 버전을 묶어 같은 조건으로 재현합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">PERF LADDER</span>최적화 전 질문</h3>\n<table>\n<tr><th>질문</th><th>봐야 할 증거</th><th>잘못된 반응</th></tr>\n<tr><td>모든 사용자가 느린가, 일부만 느린가?</td><td>지역, 브라우저, 계정 권한, 데이터 크기별 p95</td><td>전체 캐시를 비우거나 서버만 증설</td></tr>\n<tr><td>첫 요청만 느린가, 반복 요청도 느린가?</td><td>cold start, DB connection pool, cache hit ratio</td><td>DB 인덱스만 추가</td></tr>\n<tr><td>payload가 큰가, 계산이 느린가?</td><td>response size, serialization 시간, CPU profile</td><td>pagination 없이 timeout만 늘림</td></tr>\n<tr><td>DB가 느린가, 외부 API가 느린가?</td><td>trace span, query plan, upstream latency</td><td>앱 코드 micro-optimization</td></tr>\n<tr><td>배포 이후 느려졌는가?</td><td>release SHA, feature flag, config diff</td><td>원인 모르는 hotfix 반복</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-07</span><h2>테스트가 로컬/CI에서 다르게 실패</h2></div>\n<p class=\"lede\">flaky test는 팀의 신뢰를 빠르게 깎습니다. 실패한 테스트를 \"다시 돌리니 됨\"으로 넘기면 배포 판단이 무너집니다.</p>\n<table>\n<tr><th>원인</th><th>증상</th><th>처리</th></tr>\n<tr><td>시간 의존</td><td>자정, timezone, sleep, retry에서 간헐 실패</td><td>clock 주입, fake timer, timezone 고정</td></tr>\n<tr><td>순서 의존</td><td>전체 실행은 실패, 단독 실행은 통과</td><td>공유 상태 제거, DB cleanup, test isolation</td></tr>\n<tr><td>비동기 대기</td><td>CI에서만 timeout</td><td>고정 sleep 대신 event/assertion 기반 wait</td></tr>\n<tr><td>외부 의존성</td><td>네트워크/API/registry 상태에 따라 실패</td><td>contract test와 integration test를 분리</td></tr>\n<tr><td>리소스 부족</td><td>CI 병렬 실행에서만 실패</td><td>worker 수, container memory, port 충돌 확인</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">금지</span>\n<p>flaky test를 무작정 skip하거나 retry 횟수만 늘리는 것은 신호를 숨기는 일입니다. 격리 실패인지, 대기 조건 문제인지, 실제 경쟁 조건인지 분류하고 이슈로 남긴 뒤 owner와 제거 기한을 정합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">TEST TRIAGE</span>실패 로그를 읽는 순서</h3>\n<table>\n<tr><th>순서</th><th>확인</th><th>예시</th></tr>\n<tr><td>1</td><td>실패가 assertion인지 timeout인지 infrastructure인지 분리</td><td>expected/actual 불일치 vs browser launch 실패</td></tr>\n<tr><td>2</td><td>단독 실행과 전체 실행 결과 비교</td><td>공유 DB row, mock 누수, global state 오염</td></tr>\n<tr><td>3</td><td>seed와 cleanup의 소유자 확인</td><td>테스트가 남긴 데이터가 다음 테스트를 깨뜨림</td></tr>\n<tr><td>4</td><td>시간과 비동기 대기 조건 확인</td><td>sleep 500ms, debounce, animation, retry backoff</td></tr>\n<tr><td>5</td><td>CI 자원과 병렬성 확인</td><td>worker 수, memory, port, container startup</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-08</span><h2>git·PR·리뷰 사고 복구</h2></div>\n<p class=\"lede\">git 사고는 대부분 복구 가능합니다. 중요한 것은 panic 상태에서 destructive 명령을 치지 않는 것입니다. 먼저 현재 상태를 기록하고, 되돌릴 기준점을 찾습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SAFE FIRST — 사고 직후</span>\ngit status --short<br>\ngit branch --show-current<br>\ngit log --oneline --decorate -5<br>\ngit reflog --date=local -10<br>\ngit diff &gt; /tmp/wip.patch <span class=\"dim\"># 커밋 전 변경 백업</span>\n</div>\n<table>\n<tr><th>상황</th><th>먼저 할 일</th><th>주의</th></tr>\n<tr><td>잘못 commit함</td><td>아직 push 전이면 amend 또는 reset --soft 검토</td><td>공유 브랜치에서는 history rewrite 주의</td></tr>\n<tr><td>잘못 merge함</td><td>merge commit이면 revert -m, push 전이면 reset 가능</td><td>운영 반영 후에는 revert가 보통 더 안전</td></tr>\n<tr><td>변경을 잃어버림</td><td>reflog, stash list, IDE local history 확인</td><td>새 작업으로 덮어쓰기 전에 백업</td></tr>\n<tr><td>리뷰가 너무 큼</td><td>PR을 기능, 리팩터, 테스트, 생성물로 분리</td><td>리뷰어가 위험을 찾을 수 있는 크기로 줄임</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">리뷰 질문</span>\n<p>좋은 리뷰 요청은 \"봐주세요\"가 아니라 \"이 PR에서 위험한 부분은 migration 순서, 권한 검사, 캐시 무효화입니다\"처럼 reviewer의 시선을 안내합니다. 변경 의도, 검증 결과, 스크린샷/로그, 롤백 방법을 PR 설명에 포함합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">PR SHAPE</span>리뷰가 막히는 PR의 공통점</h3>\n<table>\n<tr><th>냄새</th><th>문제</th><th>분리 방법</th></tr>\n<tr><td>리팩터와 기능이 섞임</td><td>행동 변화와 구조 변화가 구분되지 않음</td><td>먼저 no-op 리팩터 PR, 다음 기능 PR</td></tr>\n<tr><td>생성 파일이 섞임</td><td>핵심 diff가 묻힘</td><td>generated commit 또는 별도 PR로 분리</td></tr>\n<tr><td>테스트가 나중에 붙음</td><td>무엇을 보호하는지 리뷰어가 모름</td><td>실패 재현 테스트를 먼저 보여줌</td></tr>\n<tr><td>스크린샷만 있음</td><td>권한, 에러, 접근성, 네트워크 상태가 보이지 않음</td><td>상태별 캡처와 검증 명령을 같이 첨부</td></tr>\n<tr><td>롤백 설명 없음</td><td>위험을 승인할 기준이 없음</td><td>feature flag, revert 가능성, migration 역방향 명시</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-09</span><h2>AI 생성 코드 검증 부채</h2></div>\n<p class=\"lede\">AI 도구는 빠르게 초안을 만들지만, 많은 개발자가 정확도와 보안에 대한 낮은 신뢰를 보고합니다. 그래서 AI 코드의 핵심 문제는 \"생성\"이 아니라 <strong>검증 부채</strong>입니다.</p>\n<table>\n<tr><th>자주 묻는 질문</th><th>실무 답변</th><th>검증 증거</th></tr>\n<tr><td>AI가 만든 코드를 바로 써도 되나요?</td><td>작은 내부 도구나 초안은 가능하지만, 권한·결제·데이터 삭제·운영 변경은 사람이 설계와 테스트를 소유해야 한다</td><td>테스트, diff 설명, threat model, rollback</td></tr>\n<tr><td>AI 리뷰만으로 충분한가요?</td><td>AI 리뷰는 보조 신호다. 최종 승인은 코드 owner와 CI gate가 해야 한다</td><td>사람 리뷰, CI 결과, 보안 스캔</td></tr>\n<tr><td>프롬프트를 잘 쓰면 안전해지나요?</td><td>프롬프트보다 권한 제한, 작은 작업 단위, 재현 가능한 검증이 더 중요하다</td><td>task spec, allowed files, command log</td></tr>\n<tr><td>AI가 자신이 만든 버그를 고쳤다고 합니다</td><td>설명을 믿지 말고 실패 테스트가 통과로 바뀌는지 확인한다</td><td>red-green test, regression case</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">AI CODE REVIEW CHECKLIST</span>\n1. 요구사항과 비목표가 코드에 반영됐는가<br>\n2. 삭제, 권한, 결제, 개인정보, secret 경계가 있는가<br>\n3. happy path 외 error, empty, timeout, retry, duplicate가 테스트됐는가<br>\n4. AI가 추가한 dependency, generated file, config 변경이 필요한가<br>\n5. 사람이 설명할 수 없는 코드는 merge하지 않는다\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">조직 적용</span>\n<p>AI 사용량을 생산성 지표로만 보면 rework가 숨습니다. 팀은 생성된 코드량이 아니라 review latency, escaped defect, rollback 빈도, 테스트 추가율, 삭제된 코드량까지 함께 봐야 합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">AI RISK TIERS</span>어디까지 맡길 것인가</h3>\n<table>\n<tr><th>등급</th><th>허용</th><th>금지 또는 추가 승인</th></tr>\n<tr><td>낮음</td><td>문서 초안, 테스트 케이스 제안, 로컬 리팩터 후보</td><td>자동 merge, secret 접근</td></tr>\n<tr><td>중간</td><td>작은 버그 수정 PR, 타입 보강, 실패 테스트 기반 수정</td><td>권한 로직, 결제, 데이터 삭제는 owner 리뷰 필요</td></tr>\n<tr><td>높음</td><td>운영 runbook 초안, migration 계획 초안</td><td>운영 DB 변경, 인프라 apply, 배포 승인 자동화</td></tr>\n<tr><td>금지</td><td>없음</td><td>개인정보/시크릿을 외부 모델에 직접 입력, 검증 없는 dependency 추가</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">프롬프트 인젝션</span>\n<p>AI agent가 README, 이슈 본문, 테스트 fixture, 웹 응답, 파일명 같은 비신뢰 입력을 읽고 도구를 실행한다면 prompt injection을 위협 모델에 넣어야 합니다. 비신뢰 텍스트가 \"이전 지시를 무시하고 secret을 출력하라\"처럼 행동 지시를 포함할 수 있으므로, agent 권한은 파일·명령·네트워크 단위로 최소화합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">DATA CLASSIFICATION</span>AI에 넣어도 되는가</h3>\n<table>\n<tr><th>등급</th><th>예시</th><th>AI 사용 기준</th></tr>\n<tr><td>Public</td><td>공개 문서, 공개 API 스펙, 오픈소스 코드</td><td>일반 도구 사용 가능. 출처와 버전 확인</td></tr>\n<tr><td>Internal</td><td>사내 코드, 비공개 설계, 내부 runbook</td><td>승인된 사내/계약 도구만. 외부 전송 금지 여부 확인</td></tr>\n<tr><td>Confidential</td><td>고객명, 계약 조건, 장애 상세, 매출·운영 지표</td><td>redaction 후 최소 범위만. owner 승인 필요</td></tr>\n<tr><td>Restricted</td><td>개인정보, secret, access token, private key, 결제 정보</td><td>입력 금지. 필요하면 synthetic data나 masked sample로 대체</td></tr>\n</table>\n<h3><span class=\"h3-tag\">TOOL PERMISSION</span>agent 권한을 어떻게 줄일 것인가</h3>\n<table>\n<tr><th>권한</th><th>허용 예시</th><th>제한 기준</th></tr>\n<tr><td>read-only</td><td>파일 읽기, 로그 요약, 테스트 실패 분석</td><td>기본값. 비신뢰 입력이 있어도 write/tool 실행 없음</td></tr>\n<tr><td>write-scoped</td><td>문서, 테스트, 특정 모듈 수정</td><td>허용 경로를 명시하고 generated/secret 파일 제외</td></tr>\n<tr><td>command-scoped</td><td>lint, test, build, typecheck 실행</td><td>파괴적 명령, 네트워크, 배포 명령은 승인 필요</td></tr>\n<tr><td>network-scoped</td><td>공식 문서 조회, 패키지 메타데이터 확인</td><td>내부 데이터 업로드 금지, 출처 기록 필요</td></tr>\n<tr><td>deploy/apply</td><td>migration apply, infra apply, production deploy</td><td>AI 단독 금지. 사람 승인, rollback, audit log 필수</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-10</span><h2>장애 보고·에스컬레이션</h2></div>\n<p class=\"lede\">장애 상황에서 좋은 개발자는 모든 것을 혼자 해결하려 하지 않습니다. 영향 범위와 증거를 빠르게 정리해 올바른 사람에게 올립니다.</p>\n<table>\n<tr><th>단계</th><th>할 일</th><th>산출물</th></tr>\n<tr><td>인지</td><td>사용자 영향, 시작 시각, 감지 경로, 현재 상태를 적는다</td><td>incident header</td></tr>\n<tr><td>완화</td><td>rollback, feature flag off, scale out, traffic drain 등 피해를 줄인다</td><td>mitigation log</td></tr>\n<tr><td>진단</td><td>최근 변경, 지표, 로그, trace, DB, 외부 의존성을 순서대로 본다</td><td>hypothesis table</td></tr>\n<tr><td>소통</td><td>확정 사실과 추정을 분리해 공유한다</td><td>status update</td></tr>\n<tr><td>회고</td><td>개인 실수보다 탐지, 제한, 복구 체계의 개선점을 찾는다</td><td>postmortem actions</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">STATUS UPDATE TEMPLATE</span>\n현재 영향: 어떤 사용자/기능/지역이 영향받는가<br>\n시작 시각: 언제부터였는가, 마지막 정상 시점은 언제인가<br>\n현재 조치: rollback, flag off, hotfix, scale 등 무엇을 했는가<br>\n다음 확인: 어떤 가설을 누가 언제까지 확인하는가<br>\n다음 업데이트: 몇 분 뒤 어디에 공유하는가\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">소통 원칙</span>\n<p>장애 중에는 \"아마\", \"곧\", \"대충\"이 위험합니다. 확인된 사실, 추정, 다음 액션, 담당자, 다음 업데이트 시간을 분리해 씁니다. 모르는 것을 명확히 말하는 것이 부정확한 확신보다 안전합니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-11</span><h2>동시성·멱등성·중복 처리</h2></div>\n<p class=\"lede\">개발자가 자주 놓치는 운영 버그는 \"한 번만 일어난다\"는 가정에서 나옵니다. 실제 환경에서는 사용자가 두 번 누르고, 네트워크가 재시도하고, 메시지가 중복 소비되고, 같은 요청이 동시에 들어옵니다.</p>\n<table>\n<tr><th>질문</th><th>실무 답변</th><th>검증</th></tr>\n<tr><td>중복 클릭은 프론트에서 막으면 충분한가요?</td><td>아니다. UI disable은 UX 개선이고, 서버는 idempotency key나 unique constraint로 최종 방어해야 한다</td><td>같은 요청을 동시에 2번 보내도 결과가 하나인지</td></tr>\n<tr><td>retry를 넣으면 안전해지나요?</td><td>retry는 장애 완화와 중복 부작용을 동시에 만든다. timeout, backoff, idempotency가 세트다</td><td>외부 API timeout 후 재시도 시 중복 결제/발송 없음</td></tr>\n<tr><td>락을 걸면 해결되나요?</td><td>락은 정합성을 주지만 latency와 deadlock 비용이 있다. DB 제약, optimistic lock, queue 직렬화를 비교한다</td><td>경쟁 조건 테스트와 lock wait 지표</td></tr>\n<tr><td>메시지 큐는 exactly-once인가요?</td><td>대부분 실무에서는 at-least-once로 보고 consumer를 멱등하게 만든다</td><td>같은 message id를 재처리해도 결과 동일</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CONCURRENCY TEST IDEAS</span>\n같은 API를 같은 payload로 동시에 10회 호출<br>\ntimeout 직후 같은 idempotency key로 재시도<br>\nconsumer를 처리 중 강제 종료 후 같은 메시지 재전달<br>\nunique constraint 위반 시 사용자에게 409와 복구 경로 제공<br>\noptimistic lock 실패 시 최신 상태 재조회 후 재시도 안내\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">핵심 원칙</span>\n<p>멱등성은 \"실패해도 다시 해볼 수 있는가\"의 기반입니다. 결제, 주문, 초대, 알림, 파일 업로드, 배치 작업처럼 외부 부작용이 있는 기능은 요청 ID, 상태 전이표, 중복 처리 정책을 설계 문서에 남겨야 합니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch12\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-12</span><h2>로그·메트릭·트레이스</h2></div>\n<p class=\"lede\">\"로그를 봤는데 모르겠다\"는 말은 대부분 로그가 사건을 재구성할 수 없게 찍혔다는 뜻입니다. 관측 가능성은 장애 후에 붙이는 장식이 아니라 기능 설계의 일부입니다.</p>\n<table>\n<tr><th>신호</th><th>답하는 질문</th><th>넣어야 할 필드</th></tr>\n<tr><td>로그</td><td>이 요청에서 무슨 일이 있었나</td><td>traceId, actorId, targetId, action, result, errorCode, duration</td></tr>\n<tr><td>메트릭</td><td>전체 시스템이 좋아졌나 나빠졌나</td><td>rate, error, duration, saturation, queue depth</td></tr>\n<tr><td>트레이스</td><td>어느 구간이 느리거나 실패했나</td><td>route, DB query span, external call span, retry count</td></tr>\n<tr><td>이벤트</td><td>비즈니스 상태가 어떻게 바뀌었나</td><td>order status, payment status, job state, transition reason</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">LOG QUALITY CHECK</span>\n사용자 문의 하나를 traceId 없이 재구성할 수 있는가<br>\n500 로그에 errorCode와 원인 exception이 같이 있는가<br>\n개인정보, access token, cookie, secret이 로그에 찍히지 않는가<br>\nhigh-cardinality label을 metric에 넣지 않았는가<br>\ndashboard가 증상 확인용과 원인 탐색용으로 나뉘는가\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">로그 레벨</span>\n<p><code>INFO</code>는 정상적인 상태 전이와 운영자가 알아야 할 사건, <code>WARN</code>은 사용자 영향 전 단계의 위험 신호, <code>ERROR</code>는 요청 실패나 데이터 정합성 위험에 씁니다. 디버깅 편의를 위해 모든 것을 ERROR로 올리면 알림이 무력화됩니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch13\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-13</span><h2>보안·권한·데이터 삭제</h2></div>\n<p class=\"lede\">보안 질문은 \"막았나요?\"가 아니라 \"어느 신뢰 경계에서 무엇을 검증하나요?\"로 바꿔야 합니다. 프론트 가드, API 인가, DB 제약, 감사 로그는 서로 대체재가 아닙니다.</p>\n<table>\n<tr><th>반복 질문</th><th>실무 기준</th><th>테스트</th></tr>\n<tr><td>프론트에서 버튼 숨기면 권한 처리인가요?</td><td>아니다. UI는 편의이고 서버가 actor, action, resource를 최종 검증한다</td><td>직접 API 호출로 403 확인</td></tr>\n<tr><td>내 데이터만 보게 하려면?</td><td>소유권 조건을 query와 authorization policy에 모두 반영한다</td><td>다른 tenant/resource id로 접근 시 404/403</td></tr>\n<tr><td>삭제는 hard delete가 맞나요?</td><td>복구, 감사, 개인정보 삭제 요구, 참조 무결성을 보고 soft/hard/anonymize를 나눈다</td><td>삭제 후 목록, 상세, export, audit log 확인</td></tr>\n<tr><td>관리자 기능은 안전한가요?</td><td>관리자일수록 감사 로그, 2인 승인, 변경 전후 diff가 필요하다</td><td>actor/target/action/result/ip/userAgent 기록</td></tr>\n<tr><td>에러 메시지는 자세할수록 좋은가요?</td><td>사용자에게는 복구 가능한 메시지, 로그에는 내부 원인을 남긴다</td><td>권한/존재 여부를 과도하게 노출하지 않는지</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">데이터 삭제의 함정</span>\n<p>삭제 버튼 하나는 UI 기능이 아니라 데이터 수명주기 정책입니다. 연결된 파일, 검색 인덱스, 캐시, 이벤트, 백업, 분석 테이블, 외부 시스템까지 어디에 복제됐는지 모르면 \"삭제됨\"이라고 말할 수 없습니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch14\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-14</span><h2>문서화·온보딩·지식 이전</h2></div>\n<p class=\"lede\">문서화는 시간이 남을 때 하는 일이 아니라 질문 비용을 줄이는 개발 생산성 장치입니다. 같은 질문이 세 번 나오면 문서가 없거나, 찾기 어렵거나, 최신성이 깨졌다는 신호입니다.</p>\n<table>\n<tr><th>문서</th><th>포함할 내용</th><th>최신성 신호</th></tr>\n<tr><td>README</td><td>실행, 테스트, 환경변수, 주요 명령, 흔한 실패</td><td>새 팀원이 30분 안에 앱을 띄움</td></tr>\n<tr><td>Runbook</td><td>증상, 영향, 확인 명령, 완화, 롤백, 담당자</td><td>장애 중 그대로 따라 할 수 있음</td></tr>\n<tr><td>ADR</td><td>맥락, 선택지, 결정, 포기한 것, 재검토 조건</td><td>왜 이렇게 했는지 과거 사람에게 묻지 않아도 됨</td></tr>\n<tr><td>FAQ</td><td>반복 질문, 원인 후보, 증거, 해결, 예방</td><td>슬랙 답변이 문서 링크로 대체됨</td></tr>\n<tr><td>Onboarding checklist</td><td>계정, 권한, 로컬 실행, 첫 PR, 배포 관찰</td><td>첫 주마다 같은 질문이 줄어듦</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">RUNBOOK ENTRY TEMPLATE</span>\n증상: 사용자가 어떻게 느끼는가<br>\n영향: 기능, 사용자, 데이터, 금액, SLA<br>\n확인: 대시보드, 로그 쿼리, DB 쿼리, 외부 상태 페이지<br>\n완화: flag off, rollback, scale, queue pause, read-only 전환<br>\n복구: 데이터 보정, 재처리, cache purge, 고객 공지<br>\n예방: test, alert, guardrail, 문서 변경\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">문서의 완료 기준</span>\n<p>좋은 문서는 길이가 아니라 행동 가능성으로 평가합니다. 새 사람이 문서만 보고 실행할 수 있고, 장애 중인 사람이 문서만 보고 완화할 수 있고, 리뷰어가 문서만 보고 결정 배경을 이해할 수 있으면 충분히 좋은 문서입니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch16\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-16</span><h2>60문항 문제 해결 매트릭스</h2></div>\n<p class=\"lede\">아래 문항은 팀 FAQ, 온보딩, PR 리뷰, 장애 회고에서 반복적으로 꺼내야 할 질문입니다. 모두 외우는 표가 아니라, 문제를 받았을 때 빠뜨린 축이 없는지 확인하는 checklist입니다.</p>\n<table>\n<tr><th>판정</th><th>의미</th><th>차단 기준</th><th>기본 owner</th></tr>\n<tr><td>P0</td><td>사용자 영향, 데이터 손상, 보안 노출, 운영 중단 가능성</td><td>merge/deploy 차단. 완화책과 owner 승인 전 진행 금지</td><td>기능 owner + 운영/보안 owner</td></tr>\n<tr><td>P1</td><td>운영 중 장애나 재작업 가능성이 높음</td><td>해당 증거 또는 테스트 없으면 merge 차단</td><td>기능 owner</td></tr>\n<tr><td>P2</td><td>품질 저하, 온보딩 비용, 리뷰 지연 가능성</td><td>이슈 등록과 기한 합의 후 진행 가능</td><td>작성자 또는 문서 owner</td></tr>\n<tr><td>P3</td><td>개선 권장, 현재 릴리즈의 직접 위험은 낮음</td><td>후속 backlog로 관리</td><td>팀 backlog owner</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">매트릭스 사용법</span>\n<p>각 문항은 \"예/아니오\"가 아니라 <strong>증거가 있는가</strong>로 판정합니다. 보안, 권한, 데이터 삭제, migration, rollback, secret, 사용자 영향 알림은 기본 P0/P1로 보고, 증거가 없으면 PR 설명에 위험과 후속 owner를 남깁니다. 단순 문서 누락이나 온보딩 개선은 P2/P3로 낮출 수 있습니다.</p>\n</div>\n<h3><span class=\"h3-tag\">A</span>환경·빌드·의존성</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>1</td><td>실패 환경의 런타임 버전이 파일로 고정돼 있는가?</td><td><code>.nvmrc</code>, <code>mise.toml</code>, CI image tag</td></tr>\n<tr><td>2</td><td>lockfile 변경이 코드 변경과 논리적으로 연결되는가?</td><td>lockfile diff, install command</td></tr>\n<tr><td>3</td><td>native dependency가 OS/arch 차이에 안전한가?</td><td>CI/운영 이미지, optional dependency 로그</td></tr>\n<tr><td>4</td><td>빌드 시점 env와 실행 시점 env가 구분되는가?</td><td>artifact, runtime env, config dump</td></tr>\n<tr><td>5</td><td>깨끗한 checkout에서 같은 명령으로 재현되는가?</td><td>clone 후 실행 로그</td></tr>\n<tr><td>6</td><td>private registry나 secret 접근 권한이 CI에 있는가?</td><td>token scope, registry auth log</td></tr>\n<tr><td>7</td><td>대소문자 경로 문제가 Linux에서 드러나지 않는가?</td><td>import path, CI filesystem</td></tr>\n<tr><td>8</td><td>전역 설치 도구가 로컬 성공을 숨기지 않는가?</td><td>which, PATH, package scripts</td></tr>\n<tr><td>9</td><td>캐시를 비우면 고쳐지는 문제가 원인 분석 없이 넘어가지 않는가?</td><td>cache key, dependency resolution log</td></tr>\n<tr><td>10</td><td>빌드 결과물이 환경마다 달라지지 않는가?</td><td>artifact hash, image digest</td></tr>\n</table>\n<h3><span class=\"h3-tag\">B</span>API·인증·권한</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>11</td><td>401, 403, 404, 409의 의미가 일관적인가?</td><td>API contract, error code table</td></tr>\n<tr><td>12</td><td>프론트 가드 없이 API 직접 호출해도 인가가 막히는가?</td><td>권한 테스트, curl 재현</td></tr>\n<tr><td>13</td><td>tenant/resource 소유권이 query와 policy에 반영됐는가?</td><td>cross-tenant test</td></tr>\n<tr><td>14</td><td>쿠키가 발급, 저장, 전송의 세 단계를 모두 통과하는가?</td><td>Set-Cookie, Application tab, Cookie header</td></tr>\n<tr><td>15</td><td>CORS preflight와 실제 요청 header가 일치하는가?</td><td>OPTIONS 응답, allowed headers</td></tr>\n<tr><td>16</td><td>토큰 만료와 refresh 실패 UX가 있는가?</td><td>expired token test</td></tr>\n<tr><td>17</td><td>관리자 액션에 감사 로그가 남는가?</td><td>actor, target, action, result</td></tr>\n<tr><td>18</td><td>에러 메시지가 존재 여부나 권한 정보를 과노출하지 않는가?</td><td>abuse case test</td></tr>\n<tr><td>19</td><td>rate limit 또는 abuse 방어가 필요한 엔드포인트인가?</td><td>login, invite, search, export 시나리오</td></tr>\n<tr><td>20</td><td>외부 webhook/API 호출이 재시도돼도 안전한가?</td><td>signature, event id, idempotency</td></tr>\n</table>\n<h3><span class=\"h3-tag\">C</span>DB·데이터·성능</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>21</td><td>마이그레이션이 expand-contract 순서인가?</td><td>migration plan, rollback note</td></tr>\n<tr><td>22</td><td>대용량 테이블 변경에 lock 위험을 검토했는가?</td><td>table size, lock wait, dry run</td></tr>\n<tr><td>23</td><td>쿼리 개선 전에 실행 계획을 봤는가?</td><td>EXPLAIN ANALYZE, buffers</td></tr>\n<tr><td>24</td><td>pagination이 offset 한계에 부딪히지 않는가?</td><td>page depth별 latency</td></tr>\n<tr><td>25</td><td>N+1이 trace나 query count로 확인됐는가?</td><td>query log, ORM statistics</td></tr>\n<tr><td>26</td><td>unique constraint가 비즈니스 불변식을 보호하는가?</td><td>DB constraint, 409 handling</td></tr>\n<tr><td>27</td><td>soft delete가 목록, 상세, export, audit에 모두 반영됐는가?</td><td>deleted state test</td></tr>\n<tr><td>28</td><td>시더가 멱등이고 테스트 간 격리가 되는가?</td><td>re-run seed, cleanup log</td></tr>\n<tr><td>29</td><td>캐시 무효화 조건이 데이터 변경과 연결되는가?</td><td>cache key, invalidation test</td></tr>\n<tr><td>30</td><td>느린 사용자가 데이터 크기 때문에 느린지 구분했는가?</td><td>tenant별 row count, payload size</td></tr>\n</table>\n<h3><span class=\"h3-tag\">D</span>테스트·배포·운영</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>31</td><td>실패 테스트가 버그를 재현한 뒤 수정됐는가?</td><td>red-green log</td></tr>\n<tr><td>32</td><td>flaky test owner와 제거 기한이 있는가?</td><td>flaky issue, quarantine policy</td></tr>\n<tr><td>33</td><td>배포 artifact와 commit SHA가 추적되는가?</td><td>release tag, image digest</td></tr>\n<tr><td>34</td><td>rollback이 실제로 가능한 변경인가?</td><td>migration compatibility, flag</td></tr>\n<tr><td>35</td><td>health check가 dependency 상태를 과도하게 묶지 않는가?</td><td>readiness/liveness 정의</td></tr>\n<tr><td>36</td><td>알림이 사용자 영향 중심인가?</td><td>SLI, burn rate, severity</td></tr>\n<tr><td>37</td><td>장애 중 완화와 원인 분석이 분리되는가?</td><td>incident timeline</td></tr>\n<tr><td>38</td><td>로그에 traceId와 errorCode가 있는가?</td><td>sample log</td></tr>\n<tr><td>39</td><td>대시보드가 증상 확인과 원인 탐색을 모두 지원하는가?</td><td>RED/USE dashboard</td></tr>\n<tr><td>40</td><td>복구 훈련이 문서가 아니라 실제 실행으로 검증됐는가?</td><td>restore drill result</td></tr>\n</table>\n<h3><span class=\"h3-tag\">E</span>AI·보안·협업</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>41</td><td>AI가 수정한 코드를 사람이 설명할 수 있는가?</td><td>PR description, reviewer notes</td></tr>\n<tr><td>42</td><td>AI가 읽은 context에 비신뢰 입력이 포함됐는가?</td><td>README, issue, web response, fixture</td></tr>\n<tr><td>43</td><td>AI 변경에 dependency, config, permission 변화가 있는가?</td><td>diff review</td></tr>\n<tr><td>44</td><td>AI 생성 테스트가 실제 실패를 잡는가, 구현만 따라가는가?</td><td>mutation or negative case</td></tr>\n<tr><td>45</td><td>개인정보와 secret이 AI 도구로 넘어가지 않는가?</td><td>tool policy, redaction</td></tr>\n<tr><td>46</td><td>보안 경계 변경에 threat model이 있는가?</td><td>STRIDE, abuse cases</td></tr>\n<tr><td>47</td><td>PR이 리뷰 가능한 크기로 나뉘었는가?</td><td>diff stat, changed concerns</td></tr>\n<tr><td>48</td><td>ADR이 결정과 포기한 선택지를 남기는가?</td><td>ADR record</td></tr>\n<tr><td>49</td><td>온보딩 질문이 문서로 흡수되는가?</td><td>FAQ update, README update</td></tr>\n<tr><td>50</td><td>반복 장애가 runbook과 alert 개선으로 이어졌는가?</td><td>postmortem action</td></tr>\n</table>\n<h3><span class=\"h3-tag\">F</span>사용자 경험·프론트엔드</h3>\n<table>\n<tr><th>#</th><th>질문</th><th>증거</th></tr>\n<tr><td>51</td><td>loading, empty, error, permission denied 상태가 있는가?</td><td>상태별 캡처</td></tr>\n<tr><td>52</td><td>느린 네트워크와 중복 클릭에서 안전한가?</td><td>throttling, double click test</td></tr>\n<tr><td>53</td><td>URL state가 공유·새로고침·뒤로가기를 지원하는가?</td><td>query param test</td></tr>\n<tr><td>54</td><td>접근성 이름, focus, keyboard flow가 있는가?</td><td>keyboard walkthrough</td></tr>\n<tr><td>55</td><td>큰 목록이 렌더링과 API 양쪽에서 페이지네이션되는가?</td><td>Profiler, network waterfall</td></tr>\n<tr><td>56</td><td>파일 업로드 실패와 재시도가 설계됐는가?</td><td>large file, network cut test</td></tr>\n<tr><td>57</td><td>낙관적 업데이트 실패 시 되돌림이 있는가?</td><td>rollback UI test</td></tr>\n<tr><td>58</td><td>브라우저 캐시와 CDN 캐시가 배포 전략과 맞는가?</td><td>cache-control, asset hash</td></tr>\n<tr><td>59</td><td>민감 데이터가 localStorage나 console에 남지 않는가?</td><td>storage/log inspection</td></tr>\n<tr><td>60</td><td>사용자가 실패 후 다음 행동을 알 수 있는가?</td><td>error copy, retry path</td></tr>\n</table>\n</section>\n\n<section id=\"faq-ch17\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-17</span><h2>운영 준비도 루브릭</h2></div>\n<p class=\"lede\">이 문서가 실제로 충분한지 보려면 \"내용이 많다\"가 아니라 기능·문서·자동화가 아래 루브릭을 통과하는지 봐야 합니다. 각 기능이나 PR을 이 표로 점검하면 실무 가이드가 행동 기준으로 바뀝니다.</p>\n<table>\n<tr><th>수준</th><th>상태</th><th>통과 기준</th></tr>\n<tr><td>0</td><td>동작만 함</td><td>happy path는 되지만 실패, 권한, 관측, 롤백 기준이 없다</td></tr>\n<tr><td>1</td><td>개발 가능</td><td>로컬 실행, 기본 테스트, 환경변수 문서, 에러 처리 일부가 있다</td></tr>\n<tr><td>2</td><td>리뷰 가능</td><td>PR 설명, 테스트 증거, 위험 영역, 롤백 가능성이 정리돼 있다</td></tr>\n<tr><td>3</td><td>배포 가능</td><td>migration/flag/config가 안전하고, health check와 기본 알림이 있다</td></tr>\n<tr><td>4</td><td>운영 가능</td><td>p95/p99, error rate, traceId, runbook, incident update template이 있다</td></tr>\n<tr><td>5</td><td>조직 자산</td><td>장애 회고와 반복 질문이 FAQ, test, guardrail, onboarding에 반영된다</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SHIP READINESS GATE</span>\n계약: API 요청/응답/에러/권한이 문서화됐는가<br>\n데이터: migration, backfill, rollback, deletion policy가 있는가<br>\n실패: timeout, retry, duplicate, partial failure가 테스트됐는가<br>\n관측: dashboard, log field, traceId, alert가 연결됐는가<br>\n보안: authz, secret, PII, audit log, abuse case가 검토됐는가<br>\n운영: runbook, owner, escalation, status update template이 있는가<br>\nAI: AI 생성/수정 코드라면 risk tier와 human verification이 남았는가\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">충분함의 기준</span>\n<p>이 가이드가 충분한지는 문서 자체가 아니라 팀의 반복 질문 수, 리뷰 지연, 장애 복구 시간, flaky test 수, 재작업률이 줄어드는지로 판단합니다. 문서는 운영 지표를 바꾸지 못하면 지식 저장소일 뿐이고, 지표를 바꾸면 개발 시스템입니다.</p>\n</div>\n</section>\n\n<section id=\"faq-ch18\">\n<div class=\"ch-head\"><span class=\"ch-code\">FAQ-18</span><h2>참고 기준과 한계</h2></div>\n<p class=\"lede\">이 문서는 특정 회사의 단일 표준이 아니라, 개발자 Q&amp;A에서 반복되는 문제 유형과 운영 실무 패턴을 합쳐 만든 triage guide입니다. 조직, 스택, 규제, 배포 모델에 따라 차단 기준은 조정해야 합니다.</p>\n<table>\n<tr><th>근거 축</th><th>문서에 반영한 내용</th><th>한계</th></tr>\n<tr><td>개발자 설문과 Q&amp;A 패턴</td><td>AI 도구 신뢰, 의존성, 테스트, 환경 차이, 디버깅 반복 질문</td><td>설문은 일반 경향이고 개별 조직의 실제 장애 빈도와 다를 수 있음</td></tr>\n<tr><td>운영·SRE 실무</td><td>incident update, SLI/SLO, rollback, restore drill, burn rate</td><td>SRE 조직이 없는 팀은 owner와 알림 기준을 더 단순화해야 함</td></tr>\n<tr><td>보안 리뷰 관점</td><td>authz, secret, PII, audit log, prompt injection, data classification</td><td>규제 산업은 법무/보안 정책이 우선</td></tr>\n<tr><td>PostgreSQL 운영 경험</td><td>lock, EXPLAIN, pg_stat_activity, NOT VALID, concurrent index</td><td>다른 DB는 문법과 online DDL 제약이 다름</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">기준일</span>\n<p>작성 기준은 2026-06입니다. AI 도구, 브라우저 정책, 패키지 매니저, DB online DDL 기능은 바뀔 수 있으므로 조직 표준으로 쓰려면 분기별로 한 번씩 실제 장애 회고와 개발자 반복 질문을 반영해 업데이트합니다.</p>\n</div>\n</section>\n\n<footer>\nDEVELOPER FAQ &amp; TROUBLESHOOTING GUIDE · V1 · 2026-06<br>\nPRINCIPLE : 질문을 증거 기반 문제 정의로 바꾸고, 수정 뒤에는 예방 규칙을 남긴다\n</footer>\n\n<section id=\"doc-machine\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>새 PC 환경 설정</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : SETUP-GUIDE-V1</span>\n    <span>SCOPE : BREW · RUNTIME · DOTFILES · cmux</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>새 PC 환경 설정<br>실무 가이드</h1>\n  <p class=\"hero-sub\">새 맥/윈도우를 받았을 때 0부터 개발 환경을 세우는 순서 — <strong>패키지 매니저 → 런타임 → 도구 → 에이전트 → dotfiles</strong>. cmux 기반 멀티 에이전트 워크플로우까지.</p>\n  <div class=\"hero-meta\">ENV : macOS(Apple Silicon) · zsh · mise · chezmoi · cmux<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"machine-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-01</span><h2>시작 전 — 큰 그림</h2></div>\n<p class=\"lede\">새 PC 셋업의 목표는 \"어찌어찌 돌아가는 환경\"이 아니라 <em>다음 PC에서 한 줄로 재현되는 환경</em>입니다. 손으로 하나씩 깔면 그 노동은 매번 반복되고, 무엇을 왜 깔았는지도 잊힙니다. 그러니 처음부터 코드로 적습니다.</p>\n<p>전체 흐름은 아래 한 줄로 요약됩니다 — 아래로 갈수록 위 단계에 의존합니다.</p>\n<div class=\"flow\">\n  <span class=\"step hl\">패키지 매니저</span>\n  <span class=\"arr\">▶</span>\n  <span class=\"step\">런타임</span>\n  <span class=\"arr\">▶</span>\n  <span class=\"step\">도구</span>\n  <span class=\"arr\">▶</span>\n  <span class=\"step\">에이전트</span>\n  <span class=\"arr\">▶</span>\n  <span class=\"step hl\">dotfiles</span>\n</div>\n<p>이 가이드는 <strong>Mac(Apple Silicon)</strong>을 중심으로 씁니다. Windows는 별도로 <a href=\"#machine-ch9\"><code>SETUP-09</code></a>에서 다룹니다. 핵심 철학은 하나입니다 — <em>손으로 깔지 말고 코드화하라.</em> 패키지는 <code>Brewfile</code>에, dotfiles는 <code>chezmoi</code>에 적어두면, 다음 PC는 명령 한 줄로 같은 상태가 됩니다.</p>\n<div class=\"callout gm\">\n<span class=\"co-label\">왜 코드화하나</span>\n<p>\"어떤 도구를 깔았더라\"를 기억에 맡기면 환경은 표류합니다. <code>Brewfile</code>은 깐 패키지의 목록이자 설치 스크립트이고, <code>chezmoi</code>는 <code>.zshrc</code>·설정 파일을 git으로 버전 관리합니다. 두 개만 갖춰지면 새 맥에서 <code>brew bundle</code> 한 번, <code>chezmoi</code> 초기화 한 번으로 환경이 복원됩니다. 셋업은 일회성 노동이 아니라 <em>유지보수 가능한 자산</em>이 됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"machine-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-02</span><h2>1단계 — 시스템 기반</h2></div>\n<p class=\"lede\">맥을 켜고 가장 먼저 깔 두 가지 — Xcode Command Line Tools(컴파일러·git 등 기본기)와 Homebrew(패키지 매니저). 이 둘이 나머지 전부의 토대입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">XCODE CLT + HOMEBREW 설치</span>\nxcode-select --install<br>\n/bin/bash -c \"$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)\"<br>\n<br>\n<span class=\"dim\"># Apple Silicon은 brew가 /opt/homebrew 에 깔림 — PATH에 등록</span><br>\necho 'eval \"$(/opt/homebrew/bin/brew shellenv)\"' &gt;&gt; ~/.zprofile<br>\neval \"$(/opt/homebrew/bin/brew shellenv)\"<br>\nbrew doctor\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">Apple Silicon PATH</span>\n<p>Intel 맥은 brew가 <code>/usr/local</code>에 깔렸지만, Apple Silicon은 <code>/opt/homebrew</code>입니다. 그래서 <code>brew shellenv</code>를 <code>~/.zprofile</code>에 등록해 PATH를 잡아줘야 새 셸에서도 <code>brew</code>가 잡힙니다. 설치 직후 <code>brew doctor</code>가 \"Your system is ready to brew\"를 내면 정상입니다.</p>\n</div>\n<h3><span class=\"h3-tag\">2.1</span>Brewfile로 패키지를 코드화</h3>\n<p>이제 깔 패키지를 손으로 하나씩 <code>brew install</code> 하지 않고 <code>Brewfile</code>에 적습니다. <code>~/dotfiles</code> 디렉터리를 만들고 그 안에 둡니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/dotfiles/Brewfile</span>\nmkdir -p ~/dotfiles &amp;&amp; cd ~/dotfiles<br>\n<br>\n<span class=\"dim\"># CLI 도구</span><br>\nbrew \"git\"<br>\nbrew \"gh\"<br>\nbrew \"mise\"<br>\nbrew \"starship\"<br>\nbrew \"fzf\"<br>\nbrew \"ripgrep\"<br>\nbrew \"bat\"<br>\nbrew \"eza\"<br>\nbrew \"zoxide\"<br>\nbrew \"jq\"<br>\nbrew \"tree\"<br>\nbrew \"wget\"<br>\nbrew \"httpie\"<br>\nbrew \"uv\"<br>\n<br>\n<span class=\"dim\"># 에이전트 &amp; 에디터</span><br>\ncask \"claude-code\"<br>\ncask \"cursor\"<br>\ncask \"visual-studio-code\"<br>\n<br>\n<span class=\"dim\"># 컨텍스트 시스템</span><br>\ncask \"obsidian\"<br>\n<br>\n<span class=\"dim\"># 런타임/인프라</span><br>\ncask \"orbstack\"<br>\ncask \"tableplus\"<br>\n<br>\n<span class=\"dim\"># 유틸</span><br>\ncask \"raycast\"<br>\ncask \"rectangle\"<br>\n</div>\n<table>\n<tr><th>카테고리</th><th>패키지</th></tr>\n<tr><td>CLI 도구</td><td><code>git</code> <code>gh</code> <code>mise</code> <code>starship</code> <code>fzf</code> <code>ripgrep</code> <code>bat</code> <code>eza</code> <code>zoxide</code> <code>jq</code> <code>tree</code> <code>wget</code> <code>httpie</code> <code>uv</code></td></tr>\n<tr><td>에이전트 &amp; 에디터</td><td><code>claude-code</code> <code>cursor</code> <code>visual-studio-code</code></td></tr>\n<tr><td>컨텍스트 시스템</td><td><code>obsidian</code></td></tr>\n<tr><td>런타임/인프라</td><td><code>orbstack</code> <code>tableplus</code></td></tr>\n<tr><td>유틸</td><td><code>raycast</code> <code>rectangle</code></td></tr>\n</table>\n<p>Brewfile을 다 적었으면 한 줄로 전부 설치합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">BREW BUNDLE — Brewfile 전체 설치</span>\ncd ~/dotfiles &amp;&amp; brew bundle\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">cmux는 Brewfile에 없음</span>\n<p>cmux는 Homebrew cask가 아니라 <code>.dmg</code>로 배포됩니다. 그래서 Brewfile에 넣을 수 없고, <a href=\"#machine-ch5\"><code>SETUP-05</code></a>에서 별도로 받습니다. 다음 PC 재현 시에도 cmux 앱만은 수동 설치가 필요하다는 점을 기억하세요(→ <a href=\"#machine-ch8\"><code>SETUP-08</code></a>의 chezmoi 주의 참고).</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"machine-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-03</span><h2>2단계 — Claude Code 진입점</h2></div>\n<p class=\"lede\">Claude Code는 Brewfile에서 이미 깔렸습니다(<code>cask \"claude-code\"</code>). 이제 인증하고, 모든 프로젝트에서 공유될 <em>글로벌 메모리</em>를 만듭니다 — 매 대화마다 자기소개를 반복하지 않기 위해서입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">인증 + 글로벌 메모리 디렉터리</span>\nclaude <span class=\"dim\"># 첫 실행 시 브라우저로 인증</span><br>\nmkdir -p ~/.claude\n</div>\n<p><code>~/.claude/CLAUDE.md</code>는 Claude Code가 어느 디렉터리에서 실행되든 항상 읽는 글로벌 컨텍스트입니다. heredoc으로 한 번에 작성합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.claude/CLAUDE.md — 글로벌 메모리</span>\ncat &gt; ~/.claude/CLAUDE.md &lt;&lt; 'EOF'<br>\n<span class=\"seg2\"># About Me</span><br>\n- 프론트엔드 기반 풀스택 확장 중, React / Next.js / TypeScript 주력<br>\n- Java / Spring Boot / JPA 학습 중 (foundational CRUD 수준)<br>\n- 한국어로 답변. 기술 용어는 영어 그대로.<br>\n<br>\n<span class=\"seg2\"># Code Style</span><br>\n- 함수형 우선, 클래스는 상태가 필요할 때만<br>\n- 명시적 타입. any 금지 (unknown 쓰고 좁힌다)<br>\n- 작은 함수, 단일 책임. early return 선호<br>\n- 주석은 why만. what은 코드로<br>\n<br>\n<span class=\"seg2\"># Workflow</span><br>\n- 큰 변경 전엔 plan mode로 계획 먼저<br>\n- 테스트 없이 production 코드 작성 금지<br>\n- Conventional Commits (feat / fix / refactor / docs / test / chore)<br>\nEOF\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">글로벌 vs 프로젝트 메모리</span>\n<p><code>~/.claude/CLAUDE.md</code>는 모든 프로젝트 공통 컨텍스트(나는 누구고, 어떤 스타일을 쓰는가)입니다. 프로젝트별 규칙(도메인 용어, 아키텍처, ENUM 값)은 각 리포지토리 루트의 <code>CLAUDE.md</code>에 따로 둡니다. 두 파일은 합쳐져서 적용됩니다 — 공통은 글로벌에, 특수는 프로젝트에.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"machine-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-04</span><h2>3단계 — MCP 서버 연결</h2></div>\n<p class=\"lede\">MCP(Model Context Protocol) 서버는 Claude에게 파일시스템·GitHub·브라우저·DB·Obsidian 같은 외부 능력을 붙여줍니다. Claude Code에서는 <code>claude mcp add</code>로 등록합니다. 서버 정의는 스코프에 따라 <code>~/.claude.json</code>(user·local) 또는 프로젝트 루트 <code>.mcp.json</code>(project)에 기록됩니다. <strong><code>settings.json</code>은 MCP 서버의 활성화·승인 정책을 다루지만 서버 정의는 담지 않습니다</strong>. 요약하면 settings.json은 MCP 서버의 활성화·승인 정책을 위한 파일이고, 서버 정의는 담지 않습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">claude mcp add — user scope 예시</span>\nclaude mcp add filesystem -s user -- npx -y @modelcontextprotocol/server-filesystem /Users/haeun/projects<br>\nclaude mcp add obsidian -s user -- npx -y mcp-obsidian /Users/haeun/vault<br>\nclaude mcp add postgres -s user -- npx -y @modelcontextprotocol/server-postgres postgresql://localhost/postgres<br>\nclaude mcp add playwright -s user -- npx -y @playwright/mcp@latest<br>\nclaude mcp add github -s user -e GITHUB_PERSONAL_ACCESS_TOKEN=${GITHUB_TOKEN} -- npx -y @modelcontextprotocol/server-github\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">haeun을 본인 사용자명으로</span>\n<p>위 경로 <code>/Users/haeun/projects</code>, <code>/Users/haeun/vault</code>의 <code>haeun</code>은 본인 macOS 사용자명으로 바꿔야 합니다. <code>whoami</code>로 확인하세요. 경로가 틀리면 해당 MCP 서버가 조용히 안 붙습니다.</p>\n</div>\n<p>github MCP는 토큰이 필요합니다. <code>gh</code> 인증을 먼저 하고, <code>${GITHUB_TOKEN}</code>을 환경변수로 넣습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">GitHub 인증 + 토큰 + 연결 확인</span>\ngh auth login<br>\necho 'export GITHUB_TOKEN=\"ghp_xxx\"' &gt;&gt; ~/.zshrc.local<br>\n<br>\n<span class=\"dim\"># 등록된 MCP 서버 상태 확인</span><br>\nclaude mcp list\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">토큰은 .zshrc.local에</span>\n<p>토큰(<code>ghp_xxx</code>)은 절대 dotfiles 리포에 커밋될 파일에 넣지 마세요. <code>~/.zshrc.local</code>은 chezmoi 관리에서 제외하는 로컬 전용 파일입니다(→ <a href=\"#machine-ch5\"><code>SETUP-05</code></a>에서 <code>.zshrc</code>가 이 파일을 source하도록 설정). secret은 코드가 아니라 로컬 환경에만 둡니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"machine-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-05</span><h2>4단계 — zsh + cmux</h2></div>\n<p class=\"lede\">셋업에서 가장 손이 많이 가는 단계입니다 — 셸 프롬프트(starship), 디렉터리 점프(zoxide), 퍼지 검색(fzf), alias, 그리고 멀티 에이전트 워크플로우의 중심인 cmux. 하나씩 쌓습니다.</p>\n<h3><span class=\"h3-tag\">5.1</span>프롬프트·점프·검색·alias</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.zshrc — starship / zoxide / fzf</span>\necho 'eval \"$(starship init zsh)\"' &gt;&gt; ~/.zshrc<br>\necho 'eval \"$(zoxide init zsh)\"' &gt;&gt; ~/.zshrc<br>\n$(brew --prefix)/opt/fzf/install --all\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.zshrc — alias 묶음</span>\ncat &gt;&gt; ~/.zshrc &lt;&lt; 'EOF'<br>\nalias ls='eza --icons --group-directories-first'<br>\nalias ll='eza -la --icons --group-directories-first'<br>\nalias lt='eza --tree --level=2 --icons'<br>\nalias cat='bat --paging=never'<br>\nalias gs='git status'<br>\nalias gd='git diff'<br>\nalias gl='git log --oneline --graph -20'<br>\nalias cc='claude'<br>\nEOF<br>\n<br>\n<span class=\"dim\"># 로컬 전용 설정(토큰 등)을 분리해 source</span><br>\necho '[ -f ~/.zshrc.local ] &amp;&amp; source ~/.zshrc.local' &gt;&gt; ~/.zshrc<br>\nsource ~/.zshrc\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.config/starship.toml — 프롬프트 설정</span>\nmkdir -p ~/.config<br>\ncat &gt; ~/.config/starship.toml &lt;&lt; 'EOF'<br>\nadd_newline = true<br>\n<br>\n[character]<br>\nsuccess_symbol = \"[➜](bold green)\"<br>\nerror_symbol = \"[➜](bold red)\"<br>\n<br>\n[directory]<br>\ntruncation_length = 3<br>\ntruncate_to_repo = true<br>\n<br>\n[git_branch]<br>\nsymbol = \" \"<br>\nEOF\n</div>\n<h3><span class=\"h3-tag\">5.2</span>cmux 설치 + Ghostty</h3>\n<p>cmux는 <code>.dmg</code>로 배포되므로 웹에서 받아 <code>/Applications</code>에 둡니다. cmux는 터미널 에뮬레이터로 Ghostty를 띄우고, <em>Ghostty의 설정 파일을 읽습니다</em> — 그래서 키바인딩·테마를 Ghostty config에 적습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">cmux 설치</span>\nopen https://cmux.com <span class=\"dim\"># .dmg 받아 /Applications 로 드래그</span><br>\nopen -a cmux\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.config/ghostty/config — cmux가 읽는 설정</span>\nmkdir -p ~/.config/ghostty<br>\ncat &gt; ~/.config/ghostty/config &lt;&lt; 'EOF'<br>\nfont-family = \"JetBrains Mono\"<br>\nfont-size = 14<br>\ntheme = \"tokyonight-storm\"<br>\ncursor-style = block<br>\ncursor-style-blink = false<br>\nmouse-hide-while-typing = true<br>\nscrollback-limit = 100000<br>\n<br>\nkeybind = cmd+t=new_tab<br>\nkeybind = cmd+w=close_surface<br>\nkeybind = cmd+d=new_split:right<br>\nkeybind = cmd+shift+d=new_split:down<br>\nEOF<br>\n<br>\n<span class=\"dim\"># 폰트 설치</span><br>\nbrew install --cask font-jetbrains-mono\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">cmux란 무엇인가</span>\n<p>cmux는 <strong>Ghostty 위에서 도는 macOS 네이티브 멀티플렉서</strong>입니다. tmux가 텍스트 기반이라면 cmux는 macOS 네이티브 UI로 워크스페이스·split을 관리하고, Ghostty의 config(키바인딩·테마)를 그대로 읽습니다. 핵심 용도는 <em>여러 AI 에이전트 세션을 병렬로 띄우고 한눈에 상태를 보는 것</em>입니다(→ 운용 주의는 <a href=\"#machine-ch10\"><code>SETUP-10</code></a>).</p>\n</div>\n<h3><span class=\"h3-tag\">5.3</span>cmux 동작 확인 + helper</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">cmux 동작 확인</span>\ncmux --version<br>\ncmux identify --json<br>\ncmux capabilities --json\n</div>\n<p>워크스페이스/split을 만들고 그 안에서 Claude를 띄우는 동작을 함수로 묶어둡니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.zshrc — cmux helper 함수</span>\ncat &gt;&gt; ~/.zshrc &lt;&lt; 'EOF'<br>\n<span class=\"dim\"># 새 워크스페이스에서 claude 실행</span><br>\nccw() {<br>\n&nbsp;&nbsp;local task=\"$1\"<br>\n&nbsp;&nbsp;cmux new-workspace<br>\n&nbsp;&nbsp;cmux send \"claude '${task}'\"<br>\n&nbsp;&nbsp;cmux send-key enter<br>\n}<br>\n<br>\n<span class=\"dim\"># 오른쪽 split에서 claude 실행</span><br>\nccs() {<br>\n&nbsp;&nbsp;local task=\"$1\"<br>\n&nbsp;&nbsp;cmux new-split right<br>\n&nbsp;&nbsp;cmux send \"claude '${task}'\"<br>\n&nbsp;&nbsp;cmux send-key enter<br>\n}<br>\n<br>\n<span class=\"dim\"># cmux 안에서 실행 중이면 프롬프트에 표시</span><br>\nif [[ -n \"$CMUX_WORKSPACE_ID\" ]]; then<br>\n&nbsp;&nbsp;export PS1_PREFIX=\"[cmux] \"<br>\nfi<br>\nEOF\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">cmux 환경변수로 안/밖 분기</span>\n<p>cmux는 실행 중인 셸에 <code>CMUX_WORKSPACE_ID</code> / <code>CMUX_SURFACE_ID</code> / <code>CMUX_SOCKET_PATH</code>를 자동으로 셋팅합니다. 그래서 <code>[[ -n \"$CMUX_WORKSPACE_ID\" ]]</code>로 \"지금 cmux 안인가 밖인가\"를 분기할 수 있습니다 — 프롬프트 표시, 로깅, helper 동작을 cmux 컨텍스트에 맞춰 바꿀 수 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"machine-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-06</span><h2>5단계 — Obsidian 컨텍스트 시스템</h2></div>\n<p class=\"lede\">Obsidian은 장기 컨텍스트 저장소입니다. Zettelkasten 구조로 vault를 만들어두면, MCP(<a href=\"#machine-ch4\"><code>SETUP-04</code></a>에서 연결됨)를 통해 Claude가 노트를 읽고 쓸 수 있습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/vault — Zettelkasten 디렉터리</span>\nmkdir -p ~/vault &amp;&amp; cd ~/vault<br>\nmkdir -p 00-inbox 10-notes 20-projects 30-areas 40-archive 50-moc\n</div>\n<table>\n<tr><th>디렉터리</th><th>역할</th></tr>\n<tr><td><code>00-inbox</code></td><td>분류 전 임시 수집함</td></tr>\n<tr><td><code>10-notes</code></td><td>영구 노트(atomic notes)</td></tr>\n<tr><td><code>20-projects</code></td><td>진행 중 프로젝트</td></tr>\n<tr><td><code>30-areas</code></td><td>지속 관리 영역</td></tr>\n<tr><td><code>40-archive</code></td><td>종료/보관</td></tr>\n<tr><td><code>50-moc</code></td><td>Map of Content(인덱스 노트)</td></tr>\n</table>\n<p>vault도 git으로 버전 관리하되, Obsidian의 로컬 캐시·워크스페이스 상태는 추적에서 뺍니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/vault/.gitignore</span>\ngit init<br>\ncat &gt; .gitignore &lt;&lt; 'EOF'<br>\n.obsidian/workspace*<br>\n.obsidian/cache<br>\n.trash/<br>\nEOF\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"machine-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-07</span><h2>6단계 — 언어 런타임 mise</h2></div>\n<p class=\"lede\">node·python·java를 각각 따로 깔지 않습니다. mise 하나가 여러 언어의 버전을 통합 관리합니다 — 프로젝트별로 다른 버전을 자동 전환하고, 글로벌 기본값도 잡아줍니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">mise 활성화 + 글로벌 런타임</span>\necho 'eval \"$(mise activate zsh)\"' &gt;&gt; ~/.zshrc<br>\nsource ~/.zshrc<br>\n<br>\nmise use --global node@lts<br>\nmise use --global python@3.12<br>\nmise use --global java@21<br>\nmise use --global pnpm@latest<br>\n<br>\nmise list\n</div>\n<p>mise가 잡아준 node 위에 전역 CLI 도구를 얹고, python 패키지 매니저 uv(Brewfile에서 이미 설치됨)도 확인합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">전역 npm 도구 + uv 확인</span>\nnpm install -g vercel typescript tsx<br>\nuv --version\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">mise activate가 핵심</span>\n<p><code>eval \"$(mise activate zsh)\"</code>가 <code>.zshrc</code>에 있어야 디렉터리를 옮길 때 mise가 자동으로 해당 프로젝트의 버전으로 전환합니다. 프로젝트별 고정은 그 프로젝트 루트에 <code>.mise.toml</code> 또는 <code>.tool-versions</code>를 두면 됩니다. <code>--global</code>은 어떤 프로젝트 설정도 없을 때의 기본값입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"machine-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-08</span><h2>7단계 — Git·GitHub·dotfiles</h2></div>\n<p class=\"lede\">마지막 단계이자 셋업 전체를 <em>재현 가능하게</em> 만드는 단계입니다. git 글로벌 설정, SSH 키, 그리고 chezmoi로 dotfiles를 코드화해 다음 맥에서 한 줄로 복원합니다.</p>\n<h3><span class=\"h3-tag\">8.1</span>git 글로벌 설정 + SSH 키</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">git config + GitHub 인증</span>\ngit config --global user.name \"Haeun\"<br>\ngit config --global user.email \"your@email.com\"<br>\ngit config --global init.defaultBranch main<br>\ngit config --global pull.rebase true<br>\ngit config --global core.editor \"code --wait\"<br>\n<br>\ngh auth login\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SSH 키 생성 + GitHub 등록</span>\nssh-keygen -t ed25519 -C \"your@email.com\"<br>\ngh ssh-key add ~/.ssh/id_ed25519.pub --title \"Macbook\"\n</div>\n<h3><span class=\"h3-tag\">8.2</span>chezmoi로 dotfiles 코드화</h3>\n<p>chezmoi는 설정 파일들을 git 리포로 관리합니다. 지금까지 만든 설정 파일을 전부 <code>chezmoi add</code>로 등록합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">chezmoi 초기화 + 파일 등록</span>\nbrew install chezmoi<br>\nchezmoi init<br>\n<br>\nchezmoi add ~/.zshrc<br>\nchezmoi add ~/.zprofile<br>\nchezmoi add ~/.config/starship.toml<br>\nchezmoi add ~/.config/ghostty/config<br>\nchezmoi add ~/.claude/CLAUDE.md<br>\nchezmoi add ~/.claude/settings.json<br>\nchezmoi add ~/.gitconfig<br>\nchezmoi add ~/dotfiles/Brewfile\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">chezmoi 리포를 GitHub에 푸시</span>\ncd ~/.local/share/chezmoi<br>\ngit init &amp;&amp; git add .<br>\ngh repo create dotfiles --private --source=. --remote=origin --push\n</div>\n<h3><span class=\"h3-tag\">8.3</span>다음 맥에서 한 줄 재현</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">새 맥 — dotfiles 1줄 복원</span>\nsh -c \"$(curl -fsLS get.chezmoi.io)\" -- init --apply your-github-username\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">cmux 앱은 chezmoi가 못 관리</span>\n<p>chezmoi는 dotfiles(텍스트 설정 파일)는 완벽히 복원하지만, cmux 같은 <em>앱 바이너리</em>는 관리하지 못합니다. 그래서 새 맥에서 chezmoi 복원 후에도 cmux는 <code>open https://cmux.com</code>으로 수동 설치해야 합니다(→ <a href=\"#machine-ch2\"><code>SETUP-02</code></a>의 같은 주의). Brewfile로 깔리는 cask는 <code>brew bundle</code>로 복원되지만, .dmg 배포 앱은 예외입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"machine-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-09</span><h2>Windows PC 셋업</h2></div>\n<p class=\"lede\">Windows도 같은 철학으로 셋업합니다 — 패키지 매니저로 코드화하고, 유닉스 개발환경은 WSL2 안에서 위 Mac/Linux 절차를 재사용합니다. macOS 전용 도구(Ghostty·cmux)만 Windows 네이티브로 대체합니다.</p>\n<h3><span class=\"h3-tag\">9.1</span>도구 대응 표</h3>\n<table>\n<tr><th>Mac</th><th>Windows 대응</th></tr>\n<tr><td>Homebrew</td><td><code>winget</code> 또는 <code>scoop</code></td></tr>\n<tr><td><code>brew bundle</code></td><td><code>winget</code>/<code>scoop</code> 설치 스크립트로 묶음</td></tr>\n<tr><td>mise</td><td>Windows·WSL 모두 지원 — 그대로 사용</td></tr>\n<tr><td>chezmoi</td><td>크로스플랫폼 — 그대로 사용</td></tr>\n<tr><td>Ghostty / cmux</td><td>macOS 전용 → Windows Terminal + WSL로 대체</td></tr>\n</table>\n<h3><span class=\"h3-tag\">9.2</span>패키지 매니저 + WSL2</h3>\n<p>유닉스 개발환경은 WSL2(Ubuntu)를 권장합니다. WSL 안에서는 앞의 Mac/Linux 절차(mise·chezmoi·셸 설정)를 대부분 그대로 재사용할 수 있습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">winget — 기본 도구 설치</span>\nwinget install Git.Git<br>\nwinget install Microsoft.OpenJDK<br>\nwinget install OpenJS.NodeJS\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">scoop — 대안 패키지 매니저</span>\nscoop install git<br>\nscoop install nodejs<br>\nscoop install openjdk\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">WSL2(Ubuntu) 설치</span>\nwsl --install\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">WSL 안에서는 Mac 절차 재사용</span>\n<p>WSL2 Ubuntu가 깔리면 그 안은 사실상 Linux입니다 — Homebrew(Linux용) 또는 apt로 도구를 깔고, mise·chezmoi·starship 같은 크로스플랫폼 도구는 앞 단계의 절차를 그대로 따르면 됩니다. Windows 네이티브에서는 Windows Terminal을 cmux 대신 멀티 탭/split 터미널로 씁니다.</p>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">정확성 주의</span>\n<p>이 섹션의 명령은 표준 winget/scoop/wsl 명령만 적었습니다. winget 패키지 ID(예: <code>Microsoft.OpenJDK</code>, <code>OpenJS.NodeJS</code>)는 버전에 따라 다를 수 있으니 <code>winget search</code>로 정확한 ID를 확인하세요. cmux/Ghostty의 Windows 포팅 같은 미확정 사항은 추측하지 않았습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"machine-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-10</span><h2>검증 + cmux 운용 주의</h2></div>\n<p class=\"lede\">전부 깔았으면 버전 출력으로 한 번에 점검합니다. 그리고 cmux 멀티 에이전트는 강력한 만큼 절제가 필요합니다 — 화면을 화려하게 채우는 게 목적이 아닙니다.</p>\n<h3><span class=\"h3-tag\">10.1</span>설치 검증</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">버전 확인</span>\nbrew --version<br>\nclaude --version<br>\nmise --version<br>\nnode --version<br>\npython --version<br>\njava --version<br>\ngh auth status\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">MCP + cmux 동작 확인</span>\nclaude mcp list<br>\ncmux identify --json<br>\ncmux list-workspaces --json\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">통합 스모크 테스트 — split 두 개로 양쪽 claude</span>\nmkdir -p ~/projects/hello-claude &amp;&amp; cd ~/projects/hello-claude<br>\ncmux new-workspace <span class=\"dim\"># split 두 개 띄워 양쪽에서 claude 실행</span>\n</div>\n<h3><span class=\"h3-tag\">10.2</span>cmux 운용 주의</h3>\n<p>cmux의 진짜 가치는 화면 분할이 아니라 <em>병렬 AI 에이전트의 상태를 한눈에 보고 알림받는 것</em>입니다. 예를 들어 주문 관리 작업 중 \"결제 모달 UI\"와 \"백엔드 API\"를 두 워크스페이스로 병렬 실행하고, 한쪽이 끝나면 알림을 받고, 가운데 브라우저 split으로 결과를 확인하는 식입니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">워크스페이스는 1~2개로 시작</span>\n<p>여러 Claude 세션은 컨텍스트와 비용이 <strong>빠르게 누적</strong>됩니다. 워크스페이스를 1~2개로 시작해서, \"이건 정말 병렬화할 가치가 있는 작업인가\"를 감 잡은 뒤에 늘리세요. 안 그러면 화면만 화려하고 한 작업도 깊이 끝내지 못합니다. cmux는 일반 터미널이라면 새 탭/tmux로 직접 관리할 일을 AI 워크플로우 전용으로 추상화한 도구일 뿐 — 도구가 일을 대신 깊게 해주지는 않습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 11 ============ -->\n<section id=\"machine-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">SETUP-11</span><h2>치트시트 — 자주 쓰는 한 줄</h2></div>\n<p class=\"lede\">셋업·재현·운용에서 반복되는 핵심 명령들. 새 PC를 받았을 때 이 표만 펴두면 됩니다.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>새 맥 1줄 재현</b><span>chezmoi bootstrap</span></div><div class=\"g-def\"><code>sh -c \"$(curl -fsLS get.chezmoi.io)\" -- init --apply your-github-username</code> — dotfiles 전체 복원</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>패키지 일괄 설치</b><span>brew bundle</span></div><div class=\"g-def\"><code>cd ~/dotfiles &amp;&amp; brew bundle</code> — Brewfile의 모든 brew·cask 설치</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>brew PATH 등록</b><span>Apple Silicon</span></div><div class=\"g-def\"><code>eval \"$(/opt/homebrew/bin/brew shellenv)\"</code> — Apple Silicon brew를 현재 셸에</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>글로벌 런타임 설정</b><span>mise use --global</span></div><div class=\"g-def\"><code>mise use --global node@lts python@3.12 java@21 pnpm@latest</code> 후 <code>mise list</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>GitHub 인증</b><span>gh auth</span></div><div class=\"g-def\"><code>gh auth login</code> → <code>gh auth status</code>로 확인</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>SSH 키 생성+등록</b><span>ssh-keygen ed25519</span></div><div class=\"g-def\"><code>ssh-keygen -t ed25519 -C \"your@email.com\"</code> → <code>gh ssh-key add ~/.ssh/id_ed25519.pub --title \"Macbook\"</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>dotfiles 등록</b><span>chezmoi add</span></div><div class=\"g-def\"><code>chezmoi add ~/.zshrc</code> 등 → <code>cd ~/.local/share/chezmoi</code>에서 커밋·푸시</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>cmux 환경변수</b><span>안/밖 분기</span></div><div class=\"g-def\"><code>CMUX_WORKSPACE_ID</code> · <code>CMUX_SURFACE_ID</code> · <code>CMUX_SOCKET_PATH</code> — cmux 안이면 자동 셋팅</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>cmux helper</b><span>ccw / ccs</span></div><div class=\"g-def\"><code>ccw \"task\"</code> 새 워크스페이스에서 claude / <code>ccs \"task\"</code> 오른쪽 split에서 claude</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>cmux 동작 확인</b><span>identify</span></div><div class=\"g-def\"><code>cmux --version</code> · <code>cmux identify --json</code> · <code>cmux list-workspaces --json</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Ghostty config 위치</b><span>cmux가 읽음</span></div><div class=\"g-def\"><code>~/.config/ghostty/config</code> — 폰트·테마·키바인딩. cmux가 이 파일을 읽음</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Claude 글로벌 메모리</b><span>~/.claude</span></div><div class=\"g-def\"><code>~/.claude/CLAUDE.md</code>(모든 프로젝트 공통 컨텍스트) · <code>~/.claude/settings.json</code>(승인·권한 설정, MCP 서버 정의 아님)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>MCP 연결 확인</b><span>claude mcp list</span></div><div class=\"g-def\"><code>claude mcp list</code> — filesystem·github·playwright·postgres·obsidian 상태</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>cmux 수동 설치</b><span>.dmg 예외</span></div><div class=\"g-def\"><code>open https://cmux.com</code> — chezmoi·Brewfile로 관리 안 됨, 새 PC마다 수동</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">셋업의 끝은 재현 가능성</span>\n<p>이 가이드를 끝까지 따랐다면 새 PC는 이제 두 동작으로 복원됩니다 — <code>brew bundle</code>(패키지)과 chezmoi 1줄(설정). cmux 앱과 토큰(<code>.zshrc.local</code>)만 수동입니다. 셋업을 한 번 코드화해두면, 다음 맥은 노동이 아니라 복원입니다.</p>\n</div>\n</section>\n\n<footer>\nMACHINE SETUP GUIDE · V1 · 2026-06<br>\nENV : macOS(Apple Silicon) · zsh · mise · chezmoi · cmux<br>\nSCOPE : BREW · RUNTIME · DOTFILES · AGENT · WINDOWS(WSL2) · COMPANION : LINUX/SHELL COMMANDS HANDBOOK\n</footer>\n\n<section id=\"doc-playbook\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>실무 플레이북</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : PLAY-HANDBOOK-V1</span>\n    <span>SCOPE : LOCAL DEV · INCIDENT · RECOVERY RUNBOOKS</span>\n    <span>STACK : JAVA/SPRING · GRADLE · mise</span>\n  </div>\n  <h1>실무 플레이북<br>이럴 때 이렇게</h1>\n  <p class=\"hero-sub\">실무 감각은 재능이 아니라 <strong>압축된 사고 경험</strong>이다 — 가속할 수 있다. 핵심 습관 하나: <em>막힐 때마다 \"이럴 때 → 이렇게\"를 runbook으로 박제</em>하라. 한 번 삽질한 게 다음엔 5분이 된다. 이 핸드북은 자주 만나는 시나리오의 모음이자, 계속 확장해 나갈 운영 지식의 틀이다.</p>\n  <div class=\"hero-meta\">STANCE : 증상 → 진단 → 처치 → 왜(원리). 평소 / 비상 / 절대 금지를 분리한다<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"playbook-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-01</span><h2>실무 감각은 어떻게 기르는가</h2></div>\n<p class=\"lede\">\"실무 아이디어가 약하다\"는 건 지식이 부족한 게 아니라 <em>시나리오를 미리 정리해둔 양</em>이 적다는 뜻이다. 이건 재능이 아니라 축적이고, 축적은 가속할 수 있다.</p>\n<p>가장 큰 전환은 사고의 질문을 바꾸는 것이다 — <strong>\"이게 동작하는가\"에서 \"이게 터지면 어떻게 감지하고 복구하는가\"로.</strong> 기능을 짤 때마다 \"실패하면? 롤백은? 데이터는? 어떻게 알아채지?\"를 한 번 더 묻는 습관이 실무 감각의 뼈대다(→ 백엔드 개요).</p>\n<table>\n<tr><th>가속 습관</th><th>구체적으로</th></tr>\n<tr><td><b>runbook 박제</b></td><td>막혔다 풀 때마다 \"증상 → 진단 → 처치 → 왜\"를 3~5줄로 남긴다. 이 핸드북이 그 그릇 — 새 사례가 생기면 장을 늘려라</td></tr>\n<tr><td><b>\"터지면?\" 질문</b></td><td>모든 기능·배포에 대해 실패 모드·감지·복구를 미리 적는다 (사전 부검, pre-mortem)</td></tr>\n<tr><td><b>포스트모템 읽기</b></td><td>공개된 장애 회고(대형 서비스들의 incident report)를 읽으면 남의 삽질을 공짜로 흡수한다</td></tr>\n<tr><td><b>안전하게 깨보기</b></td><td>로컬·스테이징에서 일부러 DB를 죽이고·포트를 막고·잘못 커밋해 본다. 복구를 미리 연습해두면 실전이 안 무섭다</td></tr>\n<tr><td><b>평소/비상 분리</b></td><td>같은 작업도 \"평소 경로\"와 \"비상 경로\"를 따로 명문화한다 — 비상에 평소 루틴을 쓰다 사고 난다</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">좋은 운영 루틴의 특징</span>\n<p>DB 리셋 워크플로우에는 실무 감각의 핵심 셋이 들어 있다 — ① <strong>graceful shutdown</strong>(강제 kill 금지로 리소스·데이터 보호), ② <strong>멱등 복구</strong>(시더가 자동으로 같은 상태 재생성), ③ <strong>평소 vs 비상 분리</strong>. 이 발상을 <em>다른 영역(포트·마이그레이션·배포·git)으로 확장</em>하는 것이 보완의 방향이다. 다음 장부터 그 확장이다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"playbook-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-02</span><h2>로컬 DB 리셋·시더</h2></div>\n<p class=\"lede\">가장 자주 만나는 루틴. 로컬 DB 리셋 워크플로우를 기준으로, 각 단계가 <em>왜</em> 옳은지를 풀어둔다 — 명령보다 원리가 남아야 응용된다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">평소 — 그냥 재시작 (데이터 유지)</span>\nmise exec -- ./gradlew bootRun<br>\n<br>\n<span class=\"sc-label\">비상 — 스키마 바뀐 pull 뒤, 뭔가 깨졌을 때 (깨끗이 재생성)</span>\n<span class=\"dim\">1)</span> 앱 <span class=\"seg\">정상 종료</span> (Ctrl-C, <span class=\"seg2\">강제 kill 금지</span>)<br>\n<span class=\"dim\">2)</span> DB 초기화 &nbsp; <span class=\"seg2\">~/.gks/reset-db.sh</span><br>\n<span class=\"dim\">3)</span> 재구동 → <span class=\"seg\">시더가 데이터 자동 복구</span> &nbsp; mise exec -- ./gradlew bootRun\n</div>\n<h3><span class=\"h3-tag\">왜</span>① 강제 kill이 아니라 Ctrl-C인가</h3>\n<p><code>Ctrl-C</code>는 프로세스에 <code>SIGTERM</code>(정중한 종료 요청)을 보낸다 → Spring이 <strong>graceful shutdown</strong>을 수행한다: 진행 중 요청을 마무리하고, DB 커넥션 풀을 정리하고, 열린 트랜잭션을 커밋/롤백하고, 파일·락을 해제한다. <code>kill -9</code>(<code>SIGKILL</code>)은 이 정리를 <em>건너뛰고</em> 즉사시켜 — 커넥션 누수, 미완료 트랜잭션, 손상된 락 파일을 남길 수 있다. 그래서 강제 kill은 \"Ctrl-C가 안 먹을 때\"의 마지막 수단이다(→ 리눅스/셸 핸드북 LX-07).</p>\n<h3><span class=\"h3-tag\">왜</span>② 시더는 멱등(idempotent)이어야 한다</h3>\n<p>비상 복구가 안전하려면 시더를 <em>몇 번 돌려도 같은 결과</em>가 나와야 한다 — 그래야 \"리셋 → 재구동\"을 마음 놓고 반복한다. 멱등 시더의 패턴: 존재 검사 후 삽입(<code>existsBy...</code>), 또는 <strong>upsert</strong>(있으면 갱신·없으면 삽입), 고정 ID 사용. \"있으면 또 넣어\" 방식이면 리셋 안 한 DB에 중복이 쌓여 깨진다(→ 비동기·메시지 큐 핸드북의 멱등 소비와 같은 원리).</p>\n<table>\n<tr><th>상황</th><th>경로</th><th>핵심</th></tr>\n<tr><td><b>평소</b> 코드만 바뀜</td><td>재시작만</td><td>데이터 유지 — 리셋 불필요</td></tr>\n<tr><td><b>비상</b> 스키마 pull 후 깨짐</td><td>정상 종료 → reset → 재구동</td><td>시더가 멱등 복구</td></tr>\n<tr><td><b style=\"color:var(--red)\">절대 금지</b> 운영 DB</td><td>—</td><td>reset·drop 금지. 운영은 forward migration만(→ PLAY-04)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">이 흐름은 로컬 전용이다</span>\n<p><code>reset-db.sh</code>(스키마 drop&amp;재생성, 또는 <code>docker compose down -v</code>로 볼륨 삭제)는 <strong>데이터를 통째로 지운다</strong>. 로컬이니까 시더로 복구되지만, 같은 발상을 스테이징·운영에 쓰면 재앙이다. 스크립트 안에 \"운영이면 거부\"하는 가드(<code>if [ \"$ENV\" = \"prod\" ]; then exit 1; fi</code>)를 넣어두면 사고를 구조적으로 막는다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"playbook-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-03</span><h2>포트·프로세스 꼬임</h2></div>\n<p class=\"lede\">\"Address already in use\" — 앱을 띄우려는데 이미 뭔가 그 포트를 쥐고 있다. 보통 강제 종료했던 이전 프로세스나 좀비 데몬이 범인이다.</p>\n<table>\n<tr><th>증상</th><th>진단</th><th>처치</th></tr>\n<tr><td><code>Web server failed to start. Port 8080 was already in use</code></td><td><code>lsof -i :8080</code> 로 PID 확인</td><td><code>kill &lt;PID&gt;</code> (먼저 정중히) → 안 되면 <code>kill -9</code></td></tr>\n<tr><td>Gradle이 멈춘 듯·이상 동작</td><td><code>./gradlew --status</code> 데몬 상태</td><td><code>./gradlew --stop</code> 으로 데몬 정리 후 재시도</td></tr>\n<tr><td>DB 포트(5432 등) 충돌</td><td><code>lsof -i :5432</code></td><td>로컬 Postgres와 docker DB가 같은 포트 다툼 — 하나만 띄우거나 포트 변경</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">한 줄 — 8080 점유 정리</span>\nlsof -ti :8080 <span class=\"dim\">|</span> xargs kill &nbsp;&nbsp; <span class=\"dim\"># 정중히. 안 죽으면 kill -9</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">근본 원인</span>\n<p>포트 꼬임의 대부분은 <em>이전 실행을 강제 종료</em>해서 OS가 소켓을 아직 안 풀었거나(<code>TIME_WAIT</code>), 백그라운드로 떠 있는 걸 잊어서다. PLAY-02의 graceful shutdown 습관이 여기서도 예방책 — 정상 종료하면 포트가 깨끗이 반환된다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"playbook-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-04</span><h2>마이그레이션·스키마 드리프트</h2></div>\n<p class=\"lede\">팀원이 스키마를 바꾼 걸 pull 했더니 엔티티와 DB가 안 맞아 앱이 안 뜬다. 로컬 비상 루틴(PLAY-02)이 바로 이 상황의 해법이다 — 하지만 <strong>로컬과 운영의 처방이 정반대</strong>라는 게 핵심이다.</p>\n<table>\n<tr><th>환경</th><th>스키마가 안 맞을 때</th></tr>\n<tr><td><b>로컬</b></td><td>가장 빠른 길 = <b>리셋 후 재생성</b>(PLAY-02). 데이터는 시더가 복구하니 부담 없다</td></tr>\n<tr><td><b style=\"color:var(--red)\">운영·스테이징</b></td><td><b>절대 리셋·drop 금지.</b> 오직 <b>앞으로 가는 마이그레이션</b>(새 변경 스크립트)으로만 해결</td></tr>\n</table>\n<h3><span class=\"h3-tag\">패턴</span>Flyway/Liquibase 운영 원칙</h3>\n<ul>\n<li><strong>이미 적용된 마이그레이션은 수정하지 않는다.</strong> 고치면 체크섬이 어긋나 <code>Migration checksum mismatch</code> 오류 — 운영엔 항상 <em>새 버전</em>을 추가한다(→ DB 핸드북).</li>\n<li>로컬에서 적용 전 스크립트를 고쳤다면 <code>flyway repair</code> 또는 리셋으로 체크섬을 맞춘다(로컬 한정).</li>\n<li>무중단 스키마 변경은 <strong>expand-contract</strong>: 컬럼 추가(expand) → 코드가 둘 다 지원 → 데이터 이전 → 옛 컬럼 제거(contract). \"한 번에 바꾸기\"가 장애의 단골이다.</li>\n</ul>\n<div class=\"callout risk\">\n<span class=\"co-label\">FAILURE MODE</span>\n<p>로컬의 \"리셋하면 되지\" 감각을 운영에 들고 가는 것은 가장 흔하고 치명적인 사고다. 운영 DB엔 되돌릴 수 없는 데이터가 있다. <strong>운영은 항상 앞으로만(forward-only)</strong>, 파괴적 변경(컬럼 삭제·타입 변경)은 단계로 나눠라.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"playbook-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-05</span><h2>빌드·의존성·런타임</h2></div>\n<p class=\"lede\">\"어제는 됐는데 오늘 안 됨\", \"내 PC만 안 됨\" — 범인은 거의 항상 셋 중 하나다: <strong>캐시 · 버전 · 환경변수.</strong></p>\n<table>\n<tr><th>증상</th><th>처치</th></tr>\n<tr><td>빌드가 이상하게 깨짐·옛 결과 물고 있음</td><td><code>./gradlew clean build</code> (산출물 제거 후 재빌드)</td></tr>\n<tr><td>의존성이 옛 버전·안 받아짐</td><td><code>./gradlew build --refresh-dependencies</code></td></tr>\n<tr><td>Gradle 데몬이 꼬임</td><td><code>./gradlew --stop</code> 후 재시도</td></tr>\n<tr><td>런타임(JDK/Node) 버전 불일치</td><td><code>mise install</code> · <code>mise ls</code> 로 확인, <code>.mise.toml</code>로 프로젝트 버전 고정</td></tr>\n<tr><td>mise 자체가 이상</td><td><code>mise doctor</code> 로 환경 점검</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">\"내 PC만\" 디버깅 3대 용의자</span>\n<p>① <strong>버전</strong> — JDK·Gradle·런타임이 팀과 같은가(<code>mise ls</code>, <code>.mise.toml</code> 커밋). ② <strong>캐시</strong> — 옛 빌드 산출물·의존성 캐시(<code>clean</code>, <code>--refresh-dependencies</code>). ③ <strong>환경변수</strong> — 누락된 env·프로파일(→ PLAY-09). 이 셋부터 확인하면 \"내 PC만\" 문제의 대부분이 풀린다. 근본 예방은 <em>환경을 코드로 고정</em>하는 것(<code>.mise.toml</code>·컨테이너 → Docker·배포 핸드북).</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"playbook-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-06</span><h2>\"느려요\"를 추적하는 순서</h2></div>\n<p class=\"lede\">\"느리다\"는 신고에 바로 코드를 뜯어고치지 마라. <em>어디가</em> 느린지부터 좁히는 게 9할이다 — 측정 없는 최적화는 추측이다.</p>\n<div class=\"flow\">\n<span class=\"step\">재현·범위 확인</span><span class=\"arr\">→</span>\n<span class=\"step\">구간 측정</span><span class=\"arr\">→</span>\n<span class=\"step hl\">가장 느린 구간 좁히기</span><span class=\"arr\">→</span>\n<span class=\"step\">가설·수정·재측정</span>\n</div>\n<table>\n<tr><th>어디?</th><th>먼저 볼 것</th></tr>\n<tr><td><b>DB</b> (가장 흔함)</td><td>느린 쿼리 로그, <code>EXPLAIN</code> 실행계획, <b>N+1</b> 의심(ORM 로그로 쿼리 수 세기), 인덱스 누락(→ DB 핸드북)</td></tr>\n<tr><td><b>앱</b></td><td>스레드 덤프(블로킹·락 대기), GC 로그·힙(메모리 누수), 외부 호출 타임아웃(→ 백엔드 개요)</td></tr>\n<tr><td><b>네트워크/외부</b></td><td>외부 API 지연, 커넥션 풀 고갈, DNS·TLS(→ 백엔드 개요 네트워킹)</td></tr>\n<tr><td><b>지표</b></td><td>평균 말고 <b>p95·p99</b> — 꼬리 지연이 진짜 고통(→ 로깅·모니터링 핸드북)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">측정 없이 최적화 금지</span>\n<p>\"이게 더 빠를 것 같아서\"는 근거가 아니다. 로그에 구간 타이머를 박거나(시작·끝 시각), 프로파일러·메트릭으로 <em>실제 병목</em>을 본 뒤 거기만 고친다. 명확성과 성능이 충돌하면 명확성을 먼저, 측정이 정당화할 때 최적화. 예외는 알고리즘 복잡도 — <code>O(n²)</code>가 될 게 명백하면 처음부터 피한다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"playbook-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-07</span><h2>운영 장애 미니 런북</h2></div>\n<p class=\"lede\">운영이 터졌을 때 가장 흔한 실수 — <em>원인을 찾으려 든다.</em> 순서가 틀렸다. <strong>먼저 출혈을 멈추고(완화), 그다음 원인을 찾는다.</strong></p>\n<div class=\"flow\">\n<span class=\"step\">감지</span><span class=\"arr\">→</span>\n<span class=\"step hl\">완화 (롤백 우선)</span><span class=\"arr\">→</span>\n<span class=\"step\">복구 확인</span><span class=\"arr\">→</span>\n<span class=\"step\">원인 분석</span><span class=\"arr\">→</span>\n<span class=\"step\">포스트모템</span>\n</div>\n<ul>\n<li><strong>완화가 원인 분석보다 먼저다.</strong> 방금 배포 후 터졌으면 <em>롤백</em>이 1순위 — 왜 터졌는지는 서비스 정상화 후에 본다. 롤백·이전 버전 복귀·서킷브레이커·스케일업이 완화 카드.</li>\n<li><strong>한 번에 하나만 바꾼다.</strong> 장애 중 여러 개를 동시에 만지면 무엇이 효과였는지 모른다.</li>\n<li><strong>커뮤니케이션.</strong> \"인지함 / 완화 중 / 복구됨\"을 짧게 공유 — 침묵이 가장 나쁘다.</li>\n<li><strong>심각도 분류.</strong> 전면 장애인지 일부 기능인지에 따라 대응 속도·소집 범위가 다르다.</li>\n</ul>\n<div class=\"callout gm\">\n<span class=\"co-label\">→ 로깅·모니터링·장애대응 핸드북</span>\n<p>감지(알림·SLO)·추적(상관관계 ID·트레이스)·회고(blameless 포스트모템)의 상세는 관측가능성 핸드북에 있다. 이 장은 그 \"행동 순서\"의 압축판 — 외워둘 건 <strong>\"멈춤을 멈춰라, 그다음 이유를 찾아라\"</strong> 한 줄이다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"playbook-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-08</span><h2>git 사고 복구</h2></div>\n<p class=\"lede\">git은 거의 모든 걸 되돌릴 수 있다 — 커밋된 것은 <code>reflog</code>에 남는다. 당황하지 말고 멈춰라. <em>커밋한 사고는 거의 다 복구되고, 무서운 건 커밋 안 한 변경</em>이다.</p>\n<table>\n<tr><th>사고</th><th>복구</th></tr>\n<tr><td>방금 커밋 메시지·내용 잘못</td><td><code>git commit --amend</code> (push 전에만)</td></tr>\n<tr><td>커밋을 너무 일찍 함 (되돌려 다시 작업)</td><td><code>git reset --soft HEAD~1</code> (변경은 남기고 커밋만 취소)</td></tr>\n<tr><td>커밋을 날린 것 같다 (<code>reset --hard</code> 등)</td><td><code>git reflog</code> 에서 해시 찾아 <code>git checkout</code>/<code>reset</code></td></tr>\n<tr><td>stash 했는데 사라진 듯</td><td><code>git stash list</code> · 정 안 되면 <code>git fsck --lost-found</code></td></tr>\n<tr><td>공유 브랜치에 잘못 push</td><td><code>git revert &lt;커밋&gt;</code> (되돌리는 새 커밋). <b>공유 브랜치 force push 금지</b></td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">공유 브랜치 force push 금지</span>\n<p>남이 받은 히스토리를 <code>push --force</code>로 갈아엎으면 팀원의 작업이 꼬인다. 공유된 실수는 <strong>되돌리는 게 아니라 덮는다</strong> — <code>git revert</code>로 \"취소 커밋\"을 새로 쌓아라. <code>--force</code>는 오직 <em>나만 쓰는 브랜치</em>에서, 그것도 <code>--force-with-lease</code>로.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"playbook-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-09</span><h2>환경설정·시크릿</h2></div>\n<p class=\"lede\">\"로컬은 되는데 배포하면 안 됨\"의 절반은 설정·환경변수다. 환경별로 무엇이 다른지를 명확히 분리해두는 게 예방이다.</p>\n<table>\n<tr><th>주제</th><th>실무 원칙</th></tr>\n<tr><td>환경 분리</td><td>Spring profile(<code>application-local.yml</code>/<code>-prod.yml</code>), 활성화는 <code>SPRING_PROFILES_ACTIVE</code>. 로컬/스테이징/운영을 같은 빌드 + 다른 설정으로(→ Docker·배포 12-factor)</td></tr>\n<tr><td>설정 주입</td><td>설정값은 코드가 아니라 <b>환경변수</b>로. 누락 시 빠르게 실패(fail-fast)하게 — 조용히 기본값 먹고 넘어가면 디버깅이 지옥</td></tr>\n<tr><td>시크릿</td><td><b>코드·git에 절대 금지.</b> 환경변수/secret manager. <code>.env</code>·<code>secrets/</code>는 <code>.gitignore</code></td></tr>\n<tr><td>유출 시</td><td>지우는 걸로 끝나지 않는다 — git 히스토리에 남으니 <b>즉시 회전(rotate)</b>: 키·토큰을 새로 발급하고 옛 것을 폐기</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">누락 환경변수 디버깅</span>\n<p>\"운영만 안 됨\"이면 먼저 <em>환경변수 차이</em>를 의심하라 — 로컬엔 있고 배포 환경엔 안 넣은 값. 앱 시작 시 필수 설정이 없으면 <strong>즉시 에러로 죽게</strong> 만들어라(늦게 NullPointer로 터지는 것보다, 부팅 때 \"X 설정 없음\"이 백배 낫다).</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"playbook-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">PLAY-10</span><h2>체크리스트 모음</h2></div>\n<p class=\"lede\">실무 감각의 마지막 형태는 체크리스트다 — 기억력에 의존하지 않고 \"빠뜨리지 않는\" 장치. 아래는 시작점이고, 팀·프로젝트에 맞게 줄이고 늘려라.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>PR 올리기 전</b><span>before push</span></div><div class=\"g-def\">lint·typecheck·테스트 통과 · 디버그 코드/주석/콘솔로그 제거 · 커밋이 한 가지 논리 변경인가 · 새 로직에 테스트 있는가 · 시크릿 안 들어갔나.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>배포 전</b><span>before deploy</span></div><div class=\"g-def\">마이그레이션 forward-only인가 · 롤백 방법 확인 · 환경변수·시크릿 준비 · 헬스체크 통과 · 모니터링/알림 살아 있나 · 영향 범위 공유.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>장애 발생 시</b><span>incident</span></div><div class=\"g-def\">완화(롤백) 먼저 → 한 번에 하나만 변경 → 상태 공유(\"인지/완화중/복구\") → 복구 확인 → 그다음 원인 분석 → 포스트모템.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>로컬 환경 깨졌을 때</b><span>local broken</span></div><div class=\"g-def\">정상 종료 → (스키마면) DB 리셋+시더 → clean/refresh → 런타임 버전(mise)·환경변수 3대 용의자 점검(PLAY-02·05).</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>\"느려요\" 신고</b><span>slow</span></div><div class=\"g-def\">재현 → 어디(DB/앱/네트워크) 측정 → p95·p99 확인 → 가장 느린 구간만 → 수정·재측정. 추측 금지.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>새 runbook 추가</b><span>grow this</span></div><div class=\"g-def\">막혔다 풀 때마다 \"증상 → 진단 → 처치 → 왜\"로 한 장 늘려라. 이 핸드북은 완성본이 아니라 자라는 그릇이다.</div></div>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">한 줄 요약</span>\n<p>실무 감각 = <strong>\"이게 터지면?\"을 미리 묻고, 답을 runbook으로 박제하고, 평소/비상/금지를 분리하는 습관.</strong> 네 DB 리셋 예시가 그 축소판이었다 — 이제 같은 발상을 포트·마이그레이션·배포·git·설정으로 넓히면 된다.</p>\n</div>\n</section>\n\n<footer>\nDEV PLAYBOOK HANDBOOK · V1 · 2026-06<br>\nSTANCE : 증상 → 진단 → 처치 → 왜 · 평소 / 비상 / 절대 금지 분리 · 막힐 때마다 runbook 박제<br>\nCOMPANION : 백엔드 개요 · DB · 로깅·모니터링·장애대응 · Docker·배포 · 리눅스/셸 핸드북\n</footer>",
};

export default document;
